"""
Parameterized generator for GH889_pandas_64788.

Source PR:    https://github.com/pandas-dev/pandas/pull/64788
Source Issue: https://github.com/pandas-dev/pandas/issues/46331

Seed varies: renames 'assert_index_equal' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH889_pandas_64788'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH889_pandas_64788'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('assert_index_equal', 'assert_index_equal' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH889_pandas_64788',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'pandas-dev/pandas',
                "pr_number": 64788,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/pandas-dev/pandas/pull/64788",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'doc/source/whatsnew/v3.1.0.rst': '.. _whatsnew_310:\n\nWhat\'s new in 3.1.0 (Month XX, 2026)\n------------------------------------\n\nThese are the changes in pandas 3.1.0. See :ref:`release` for a full changelog\nincluding other versions of pandas.\n\n{{ header }}\n\n.. ---------------------------------------------------------------------------\n.. _whatsnew_310.enhancements:\n\nEnhancements\n~~~~~~~~~~~~\n\n.. _whatsnew_310.enhancements.enhancement1:\n\nenhancement1\n^^^^^^^^^^^^\n\n.. _whatsnew_310.enhancements.enhancement2:\n\nenhancement2\n^^^^^^^^^^^^\n\n.. _whatsnew_310.enhancements.other:\n\nOther enhancements\n^^^^^^^^^^^^^^^^^^\n- :meth:`.DataFrameGroupBy.agg` now allows for the provided ``func`` to return a NumPy array (:issue:`63957`)\n- Added :meth:`ExtensionArray.count` (:issue:`64450`)\n- Display formatting for float sequences in DataFrame cells now respects the ``display.precision`` option (:issue:`60503`).\n- Improved the precision of float parsing in :func:`read_csv` (:issue:`64395`)\n- Improved the string ``repr`` of :class:`pd.core.arrays.SparseArray` (:issue:`64547`)\n\n.. ---------------------------------------------------------------------------\n.. _whatsnew_310.notable_bug_fixes:\n\nNotable bug fixes\n~~~~~~~~~~~~~~~~~\n\nThese are bug fixes that might have notable behavior changes.\n\n.. _whatsnew_310.notable_bug_fixes.notable_bug_fix1:\n\nnotable_bug_fix1\n^^^^^^^^^^^^^^^^\n\n.. _whatsnew_310.notable_bug_fixes.notable_bug_fix2:\n\nnotable_bug_fix2\n^^^^^^^^^^^^^^^^\n\n.. ---------------------------------------------------------------------------\n.. _whatsnew_310.api_breaking:\n\nBackwards incompatible API changes\n~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n\n.. _whatsnew_310.api_breaking.deps:\n\nIncreased minimum versions for dependencies\n^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\nSome minimum supported versions of dependencies were updated.\nIf installed, we now require:\n\n+-----------------+-----------------+----------+---------+\n| Package         | Minimum Version | Required | Changed |\n+=================+=================+==========+=========+\n|                 |                 |    X     |    X    |\n+-----------------+-----------------+----------+---------+\n\nFor `optional libraries <https://pandas.pydata.org/docs/getting_started/install.html>`_ the general recommendation is to use the latest version.\nThe following table lists the lowest version per library that is currently being tested throughout the development of pandas.\nOptional libraries below the lowest tested version may still work, but are not considered supported.\n\n+-----------------+-----------------+---------+\n| Package         | Minimum Version | Changed |\n+=================+=================+=========+\n|                 |                 |    X    |\n+-----------------+-----------------+---------+\n\nSee :ref:`install.dependencies` and :ref:`install.optional_dependencies` for more.\n\n.. _whatsnew_310.api_breaking.other:\n\nOther API changes\n^^^^^^^^^^^^^^^^^\n- APIs that accept an ``engine="numba"`` parameter with ``engine_kwargs`` will no longer pass through a ``nopython`` argument to ``numba.jit``. This argument has had no effect since numba 0.59.0 (:issue:`64483`).\n-\n\n.. ---------------------------------------------------------------------------\n.. _whatsnew_310.deprecations:\n\nDeprecations\n~~~~~~~~~~~~\n- Deprecated :meth:`.DataFrameGroupBy.agg` and :meth:`.Resampler.agg` unpacking a scalar when the provided ``func`` returns a Series or array of length 1; in the future this will result in the Series or array being in the result. Users should unpack the scalar in ``func`` itself (:issue:`64014`)\n- Deprecated :meth:`ExcelFile.parse`, use :func:`read_excel` instead (:issue:`58247`)\n- Deprecated arithmetic operations between pandas objects (:class:`DataFrame`, :class:`Series`, :class:`Index`, and pandas-implemented :class:`ExtensionArray` subclasses) and list-likes other than ``list``, ``np.ndarray``, :class:`ExtensionArray`, :class:`Index`, :class:`Series`, :class:`DataFrame`. For e.g. ``tuple`` or ``range``, explicitly cast these to a supported object instead. In a future version, these will be treated as scalar-like for pointwise operation (:issue:`62423`)\n- Deprecated automatic dtype promotion when reindexing with a ``fill_value`` that cannot be held by the original dtype. Explicitly cast to a common dtype instead (:issue:`53910`)\n- Deprecated passing unnecessary ``*args`` and ``**kwargs`` to :meth:`.GroupBy.cumsum`, :meth:`.GroupBy.cumprod`, :meth:`.GroupBy.cummin`, :meth:`.GroupBy.cummax`, :meth:`.SeriesGroupBy.skew`, :meth:`.DataFrameGroupBy.skew`, :meth:`.SeriesGroupBy.take`, and :meth:`.DataFrameGroupBy.take`. The ``skipna`` parameter for the cum* methods is now an explicit keyword argument (:issue:`50407`)\n- Deprecated the ``.name`` property of offset objects (e.g., :class:`~pandas.tseries.offsets.Day`, :class:`~pandas.tseries.offsets.Hour`). Use ``.rule_code`` instead (:issue:`64207`)\n- Deprecated the ``xlrd`` and ``pyxlsb`` engines in :func:`read_excel`. Use ``engine="calamine"`` instead (:issue:`56542`)\n- Deprecated the default value of ``exact`` in :func:`assert_index_equal`; in a future version this will default to ``True`` instead of "equiv" (:issue:`57436`)\n-\n\n.. ---------------------------------------------------------------------------\n.. _whatsnew_310.performance:\n\nPerformance improvements\n~~~~~~~~~~~~~~~~~~~~~~~~\n- Performance improvement in casting integer and boolean dtypes to ``string[pyarrow]`` by using PyArrow\'s native cast instead of element-wise conversion (:issue:`56505`)\n- Performance improvement in :meth:`DataFrame.__getitem__` when selecting a\n  single column by label on a :class:`DataFrame` with duplicate column names.\n  (:issue:`64126`).\n- Performance improvement in :attr:`Series.is_monotonic_increasing` and :attr:`Series.is_monotonic_decreasing` for :class:`ArrowDtype` and masked dtypes by dispatching to the :class:`ExtensionArray` (:issue:`56619`)\n- Performance improvement in :class:`GroupBy` reductions and transformations for :class:`SparseDtype` columns, which now use Cython instead of falling back to slow Python aggregation (:issue:`36123`)\n- Performance improvement in :func:`bdate_range` and :func:`date_range` with ``freq="B"`` or ``freq="C"`` (business day frequencies) (:issue:`16463`)\n- Performance improvement in :func:`infer_freq` (:issue:`64463`)\n- Performance improvement in :func:`merge` and :meth:`DataFrame.join` for many-to-many joins with ``sort=False`` (:issue:`56564`)\n- Performance improvement in :func:`merge` with ``how="cross"`` (:issue:`38082`)\n- Performance improvement in :func:`merge` with ``how="left"`` (:issue:`64370`)\n- Performance improvement in :func:`read_csv` with ``engine="c"`` when reading from binary file-like objects (e.g. PyArrow S3 file handles) by avoiding unnecessary ``TextIOWrapper`` wrapping (:issue:`46823`)\n- Performance improvement in :func:`read_html` and the Python CSV parser when ``thousands`` is set, fixing catastrophic regex backtracking on cells with many comma-separated digit groups followed by non-numeric text (:issue:`52619`)\n- Performance improvement in :func:`read_sas` for compressed SAS7BDAT files by reusing the decompression buffer instead of allocating per row (:issue:`47339`)\n- Performance improvement in :func:`util.hash_pandas_object` for PyArrow-backed string and binary types by using PyArrow\'s ``dictionary_encode`` instead of converting to NumPy for factorization (:issue:`48964`)\n- Performance improvement in :meth:`DataFrame.insert` when the number of blocks is small (:issue:`57641`)\n- Performance improvement in :meth:`DataFrame.loc` with non-unique masked index (:issue:`56759`)\n- Performance improvement in :meth:`DataFrame.query` and :meth:`DataFrame.eval` when the :class:`DataFrame` contains :class:`PeriodDtype` or :class:`IntervalDtype` columns (:issue:`35247`)\n- Performance improvement in :meth:`DataFrame.to_stata` when writing object-dtype datetime columns with date formats that require year/month extraction (:issue:`64555`)\n- Performance improvement in :meth:`GroupBy.any` and :meth:`GroupBy.all` for boolean-dtype columns (:issue:`37850`)\n- Performance improvement in :meth:`GroupBy.first` and :meth:`GroupBy.last` for Extension Array dtypes, which no longer fall back to a slow ``apply``-based implementation (:issue:`57591`)\n- Performance improvement in :meth:`GroupBy.quantile` (:issue:`64330`)\n- Performance improvement in :meth:`Index.get_indexer` for large monotonic indexes, which now uses binary search instead of building a hash table when the number of targets is small (:issue:`14273`)\n- Performance improvement in :meth:`NDFrame.__finalize__`, :meth:`Series.to_numpy`, :attr:`DataFrame.dtypes`, and :meth:`DataFrame.__getitem__` by reducing overhead from metadata propagation, memory sharing checks, and attribute setting (:issue:`57431`)\n- Performance improvement in :meth:`arrays.SparseArray.isna` by avoiding a dense-then-resparsify round-trip (:issue:`41023`)\n- Performance improvement in datetime/timedelta unit conversion (e.g. ``datetime64[s]`` to ``datetime64[ns]``) (:issue:`35025`)\n- Performance improvement in indexing a :class:`DataFrame` with a :class:`CategoricalIndex` of :class:`Interval` categories (:issue:`61928`)\n- Performance improvement in partial-string indexing on a monotonic decreasing :class:`DatetimeIndex` or :class:`PeriodIndex` (:issue:`64811`)\n- Performance improvement in plotting :class:`DatetimeIndex` with multiplied frequencies (e.g. ``"1000ms"``, ``"100s"``) (:issue:`50355`)\n- Performance improvement in reading zip-compressed files (e.g. :func:`read_pickle`, :func:`read_csv`) on Python < 3.12 (:issue:`59279`)\n- Performance improvement in repr of :class:`Series` and :class:`DataFrame` containing third-party array-like objects (e.g. xarray ``DataArray``) in object dtype columns (:issue:`61809`)\n\n.. ---------------------------------------------------------------------------\n.. _whatsnew_310.bug_fixes:\n\nBug fixes\n~~~~~~~~~\n- Bug in object-dtype hash table operations (``factorize``, ``unique``, ``duplicated``, ``isin``, ``value_counts``, ``groupby``, ``Index.get_loc``) not distinguishing between ``int`` and ``bool`` values, e.g. treating ``0`` and ``False`` as equal (:issue:`62888`)\n- Fix bug in :func:`to_datetime` that could give an unnecessary ``RuntimeWarning`` when converting DataFrame containing missing values (:issue:`64141`)\n\nCategorical\n^^^^^^^^^^^\n-\n-\n\nDatetimelike\n^^^^^^^^^^^^\n- Bug in :class:`Timestamp` constructor where passing ``np.str_`` objects would fail in Cython string parsing (:issue:`48974`)\n- Bug in :class:`Timestamp` constructor, :class:`Timedelta` constructor, :func:`to_datetime`, and :func:`to_timedelta` with non-round ``float`` input and ``unit`` failing to raise when the value is just outside the representable bounds (:issue:`57366`)\n- Bug in :func:`to_datetime` and :func:`to_timedelta` on ARM platforms where round ``float`` values outside the int64 domain (e.g. ``float(2**63)``) could silently produce incorrect results instead of raising (:issue:`64619`)\n- Bug in :func:`to_datetime` and :func:`to_timedelta` where ``uint64`` values greater than ``int64`` max silently overflowed instead of raising :class:`OutOfBoundsDatetime` or :class:`OutOfBoundsTimedelta` (:issue:`60677`)\n- Bug in :meth:`DatetimeArray.isin` and :meth:`TimedeltaArray.isin` where mismatched resolutions could silently truncate finer-resolution values, leading to false matches (:issue:`64545`)\n\nTimedelta\n^^^^^^^^^\n- Bug in :func:`to_timedelta` where passing ``np.str_`` objects would fail in Cython string parsing (:issue:`48974`)\n-\n\nTimezones\n^^^^^^^^^\n- Bug in :class:`DatetimeIndex` addition with a :class:`DateOffset` that has only timedelta components (e.g. ``DateOffset(hours=-2)``) raising ``ValueError`` near DST transitions, while scalar :class:`Timestamp` addition worked correctly (:issue:`28610`)\n-\n\nNumeric\n^^^^^^^\n- Fixed bug in :func:`read_excel` where having a column with mixture of numeric and boolean values will typecast the values based on the first appearance data type since 1==True and 0==False (:issue:`60088`)\n- Fixed bug in :meth:`Series.clip` where passing a scalar numpy array (e.g. ``np.array(0)``) would raise a ``TypeError`` (:issue:`59053`)\n- Fixed bug in :meth:`Series.mean` and :meth:`Series.sum` (and their :class:`DataFrame` counterparts) overflowing for ``float16`` dtypes instead of upcasting to ``float64`` (:issue:`43929`)\n- Fixed bug in :meth:`Series.skew` and :meth:`Series.kurt` (and their :class:`DataFrame` counterparts) returning ``0.0`` for degenerate distributions; these now return ``NaN`` (:issue:`62864`)\n\nConversion\n^^^^^^^^^^\n- Fixed :func:`pandas.array` to preserve mask information when converting NumPy masked arrays, converting masked values to missing values (:issue:`63879`).\n- Fixed bug in :meth:`DataFrame.convert_dtypes` where values were dropped from sliced :class:`DataFrame` objects with mixed dtypes when the internal block structure spanned multiple columns (:issue:`64702`)\n- Fixed bug in :meth:`DataFrame.from_records` where ``exclude`` was ignored when ``data`` was an iterator and ``nrows=0`` (:issue:`63774`)\n-\n\nStrings\n^^^^^^^\n-\n-\n\nInterval\n^^^^^^^^\n-\n-\n\nIndexing\n^^^^^^^^\n- Bugs in setitem-with-expansion when adding new rows failing to keep the original dtype in some cases (:issue:`32346`, :issue:`15231`, :issue:`47503`, :issue:`6485`, :issue:`25383`, :issue:`52235`, :issue:`17026`, :issue:`56010`)\n- Bug in :meth:`DataFrame.iloc` setitem raising ``AttributeError`` when assigning a :class:`Series` or :class:`Index` with a nullable EA dtype (e.g. ``Int64``, ``Float64``, ``boolean``) into a column with a NumPy dtype (:issue:`47776`)\n- Bug in :meth:`DataFrame.where` and :meth:`DataFrame.mask` raising ``TypeError`` when ``cond`` is a :class:`Series` and ``axis=1`` (:issue:`58190`)\n- Bug in :meth:`DataFrame.xs` where ``drop_level=False`` was ignored for fully specified :class:`MultiIndex` keys when ``level`` was not explicitly provided (:issue:`6507`)\n- Bug in :meth:`Index.get_level_values` mishandling boolean, NA-like (``np.nan``, ``pd.NA``, ``pd.NaT``) and integer index names (:issue:`62169`)\n- Bug in :meth:`Index.get_loc` raising ``KeyError`` when looking up a tuple in an object-dtype :class:`Index` with duplicates (:issue:`37800`)\n- Bug in :meth:`Index.insert` silently casting booleans to numeric when used with nullable numeric dtypes like ``Float64`` or ``Int64`` (:issue:`61709`)\n- Bug in :meth:`MultiIndex.loc` returning incorrect results when indexing with :class:`numpy.datetime64` on a level containing :class:`datetime.date` objects (:issue:`55969`)\n\nMissing\n^^^^^^^\n-\n-\n\nMultiIndex\n^^^^^^^^^^\n- Bug in :meth:`MultiIndex.sortlevel` not raising ``TypeError`` when sorting a level with incomparable types (e.g., ``Timestamp`` and ``str``) (:issue:`21136`)\n-\n\nI/O\n^^^\n- Fixed bug in :func:`read_csv` with the ``c`` engine where an embedded ``\\r`` followed by a space in an unquoted field could cause an infinite re-parsing loop, producing spurious rows or a buffer overflow (:issue:`51141`)\n- Fixed bug in :func:`read_excel` where usage of ``skiprows`` could lead to an infinite loop (:issue:`64027`)\n- Fixed :func:`read_json` with ``lines=True`` and ``chunksize`` to respect ``nrows``\n  when the requested row count is not a multiple of the chunk size (:issue:`64025`)\n- Fixed :func:`read_json` with ``lines=True`` and ``nrows=0`` to return an empty DataFrame (:issue:`64025`)\n\nPeriod\n^^^^^^\n- Bug in :class:`Period` constructor where passing ``np.str_`` objects would fail in Cython string parsing (:issue:`48974`)\n-\n\nPlotting\n^^^^^^^^\n-\n-\n\nGroupby/resample/rolling\n^^^^^^^^^^^^^^^^^^^^^^^^\n- Bug in :meth:`.DataFrameGroupBy.agg` when there are no groups, multiple keys, and ``group_keys=False`` (:issue:`51445`)\n- Bug in :meth:`.DataFrameGroupBy.agg` would operate on the group as a whole when ``args`` or ``kwargs`` are supplied for the provided ``func``; now this method only operates on each Series of the group (:issue:`39169`)\n- Bug in :meth:`.Rolling.skew` and :meth:`.Rolling.kurt` (and their :class:`GroupBy` counterparts) returning ``0.0`` and ``-3.0`` respectively for degenerate windows or groups; these now return ``NaN`` (:issue:`62864`)\n- Bug in :meth:`.Rolling.skew` and :meth:`.Rolling.kurt` returning ``NaN`` for low-variance windows (:issue:`62946`)\n\nReshaping\n^^^^^^^^^\n- Bug in :func:`merge` where merging on a :class:`MultiIndex` containing ``NaN`` values mapped ``NaN`` keys to the last level value instead of ``NaN`` (:issue:`64492`)\n- In :func:`pivot_table`, when ``values`` is empty, the aggregation will be computed on a Series of all NA values (:issue:`46475`)\n-\n\nSparse\n^^^^^^\n- Bug in indexing a :class:`SparseArray` with an out-of-bounds integer with the value of the length of the array returning the fill value instead of raising an ``IndexError`` (:issue:`64183`).\n-\n\nExtensionArray\n^^^^^^^^^^^^^^\n- Fixed bug in :meth:`Series.apply` and :meth:`Series.map` where nullable integer dtypes were converted to float, causing precision loss for large integers; now the nullable dtype will be preserved (:issue:`63903`).\n-\n-\n\nStyler\n^^^^^^\n-\n-\n\nOther\n^^^^^\n\n.. ***DO NOT USE THIS SECTION***\n\n-\n-\n\n.. ---------------------------------------------------------------------------\n.. _whatsnew_310.contributors:\n\nContributors\n~~~~~~~~~~~~\n',
            'pandas/core/arrays/datetimes.py': 'from __future__ import annotations\n\nfrom datetime import (\n    datetime,\n    timedelta,\n    tzinfo,\n)\nfrom typing import (\n    TYPE_CHECKING,\n    Self,\n    TypeVar,\n    cast,\n    overload,\n)\nimport warnings\n\nimport numpy as np\n\nfrom pandas._config import using_string_dtype\nfrom pandas._config.config import get_option\n\nfrom pandas._libs import (\n    lib,\n    tslib,\n)\nfrom pandas._libs.tslibs import (\n    BaseOffset,\n    NaT,\n    NaTType,\n    OutOfBoundsDatetime,\n    OutOfBoundsTimedelta,\n    Resolution,\n    Timestamp,\n    astype_overflowsafe,\n    fields,\n    get_resolution,\n    get_supported_dtype,\n    get_unit_from_dtype,\n    ints_to_pydatetime,\n    is_date_array_normalized,\n    is_supported_dtype,\n    is_unitless,\n    normalize_i8_timestamps,\n    timezones,\n    to_offset,\n    tz_convert_from_utc,\n    tzconversion,\n)\nfrom pandas._libs.tslibs.dtypes import abbrev_to_npy_unit\nfrom pandas._libs.tslibs.offsets import RelativeDeltaOffset\nfrom pandas.errors import PerformanceWarning\nfrom pandas.util._decorators import set_module\nfrom pandas.util._exceptions import find_stack_level\nfrom pandas.util._validators import validate_inclusive\n\nfrom pandas.core.dtypes.common import (\n    DT64NS_DTYPE,\n    INT64_DTYPE,\n    is_bool_dtype,\n    is_float_dtype,\n    is_string_dtype,\n    pandas_dtype,\n)\nfrom pandas.core.dtypes.dtypes import (\n    DatetimeTZDtype,\n    ExtensionDtype,\n    PeriodDtype,\n)\nfrom pandas.core.dtypes.missing import isna\n\nfrom pandas.core.arrays import datetimelike as dtl\nfrom pandas.core.arrays._ranges import (\n    generate_daily_offset_range,\n    generate_regular_range,\n)\nimport pandas.core.common as com\n\nfrom pandas.tseries.frequencies import get_period_alias\nfrom pandas.tseries.offsets import (\n    Day,\n    Tick,\n)\n\nif TYPE_CHECKING:\n    from collections.abc import (\n        Callable,\n        Generator,\n        Iterator,\n    )\n\n    from pandas._typing import (\n        ArrayLike,\n        DateTimeErrorChoices,\n        DtypeObj,\n        IntervalClosedType,\n        TimeAmbiguous,\n        TimeNonexistent,\n        TimeUnit,\n        npt,\n    )\n\n    from pandas import (\n        DataFrame,\n        Timedelta,\n    )\n    from pandas.core.arrays import PeriodArray\n\n    _TimestampNoneT1 = TypeVar("_TimestampNoneT1", Timestamp, None)\n    _TimestampNoneT2 = TypeVar("_TimestampNoneT2", Timestamp, None)\n\n\n_ITER_CHUNKSIZE = 10_000\n\n\n@overload\ndef tz_to_dtype(tz: tzinfo, unit: TimeUnit = ...) -> DatetimeTZDtype: ...\n\n\n@overload\ndef tz_to_dtype(tz: None, unit: TimeUnit = ...) -> np.dtype[np.datetime64]: ...\n\n\ndef tz_to_dtype(\n    tz: tzinfo | None, unit: TimeUnit = "ns"\n) -> np.dtype[np.datetime64] | DatetimeTZDtype:\n    """\n    Return a datetime64[ns] dtype appropriate for the given timezone.\n\n    Parameters\n    ----------\n    tz : tzinfo or None\n    unit : str, default "ns"\n\n    Returns\n    -------\n    np.dtype or DatetimeTZDtype\n    """\n    if tz is None:\n        return np.dtype(f"M8[{unit}]")\n    else:\n        return DatetimeTZDtype(tz=tz, unit=unit)\n\n\ndef _field_accessor(name: str, field: str, docstring: str | None = None):\n    def f(self):\n        values = self._local_timestamps()\n\n        if field in self._bool_ops:\n            result: np.ndarray\n\n            if field.endswith(("start", "end")):\n                freq = self.freq\n                month_kw = 12\n                if freq:\n                    kwds = freq.kwds\n                    month_kw = kwds.get("startingMonth", kwds.get("month", month_kw))\n\n                if freq is not None:\n                    freq_name = freq.rule_code\n                else:\n                    freq_name = None\n                result = fields.get_start_end_field(\n                    values, field, freq_name, month_kw, reso=self._creso\n                )\n            else:\n                result = fields.get_date_field(values, field, reso=self._creso)\n\n            # these return a boolean by-definition\n            return result\n\n        result = fields.get_date_field(values, field, reso=self._creso)\n        result = self._maybe_mask_results(result, fill_value=None, convert="float64")\n\n        return result\n\n    f.__name__ = name\n    f.__doc__ = docstring\n    return property(f)\n\n\n@set_module("pandas.arrays")\nclass DatetimeArray(dtl.TimelikeOps, dtl.DatelikeOps):\n    """\n    Pandas ExtensionArray for tz-naive or tz-aware datetime data.\n\n    .. warning::\n\n       DatetimeArray is currently experimental, and its API may change\n       without warning. In particular, :attr:`DatetimeArray.dtype` is\n       expected to change to always be an instance of an ``ExtensionDtype``\n       subclass.\n\n    Parameters\n    ----------\n    data : Series, Index, DatetimeArray, ndarray\n        The datetime data.\n\n        For DatetimeArray `values` (or a Series or Index boxing one),\n        `dtype` and `freq` will be extracted from `values`.\n\n    dtype : numpy.dtype or DatetimeTZDtype\n        Note that the only NumPy dtypes allowed are \'datetime64[ns]\',\n        \'datetime64[us]\', \'datetime64[ms]\', \'datetime64[s]\'.\n    freq : str or Offset, optional\n        The frequency.\n    copy : bool, default False\n        Whether to copy the underlying array of values.\n\n    Attributes\n    ----------\n    None\n\n    Methods\n    -------\n    None\n\n    See Also\n    --------\n    DatetimeIndex : Immutable Index for datetime-like data.\n    Series : One-dimensional labeled array capable of holding datetime-like data.\n    Timestamp : Pandas replacement for python datetime.datetime object.\n    to_datetime : Convert argument to datetime.\n    period_range : Return a fixed frequency PeriodIndex.\n\n    Examples\n    --------\n    >>> pd.arrays.DatetimeArray._from_sequence(\n    ...     pd.DatetimeIndex(["2023-01-01", "2023-01-02"], freq="D")\n    ... )\n    <DatetimeArray>\n    [\'2023-01-01 00:00:00\', \'2023-01-02 00:00:00\']\n    Length: 2, dtype: datetime64[us]\n    """\n\n    _typ = "datetimearray"\n    _recognized_scalars = (datetime, np.datetime64)\n    _is_recognized_dtype: Callable[[DtypeObj], bool] = lambda x: (\n        lib.is_np_dtype(x, "M") or isinstance(x, DatetimeTZDtype)\n    )\n    _infer_matches = ("datetime", "datetime64", "date")\n\n    @property\n    def _internal_fill_value(self) -> np.datetime64:\n        return np.datetime64("NaT", self.unit)\n\n    @property\n    def _scalar_type(self) -> type[Timestamp]:\n        return Timestamp\n\n    # define my properties & methods for delegation\n    _bool_ops: list[str] = [\n        "is_month_start",\n        "is_month_end",\n        "is_quarter_start",\n        "is_quarter_end",\n        "is_year_start",\n        "is_year_end",\n        "is_leap_year",\n    ]\n    _field_ops: list[str] = [\n        "year",\n        "month",\n        "day",\n        "hour",\n        "minute",\n        "second",\n        "weekday",\n        "dayofweek",\n        "day_of_week",\n        "dayofyear",\n        "day_of_year",\n        "quarter",\n        "days_in_month",\n        "daysinmonth",\n        "microsecond",\n        "nanosecond",\n    ]\n    _other_ops: list[str] = ["date", "time", "timetz"]\n    _datetimelike_ops: list[str] = (\n        _field_ops + _bool_ops + _other_ops + ["unit", "freq", "tz"]\n    )\n    _datetimelike_methods: list[str] = [\n        "to_period",\n        "tz_localize",\n        "tz_convert",\n        "normalize",\n        "strftime",\n        "round",\n        "floor",\n        "ceil",\n        "month_name",\n        "day_name",\n        "as_unit",\n    ]\n\n    # ndim is inherited from ExtensionArray, must exist to ensure\n    #  Timestamp.__richcmp__(DateTimeArray) operates pointwise\n\n    # ensure that operations with numpy arrays defer to our implementation\n    __array_priority__ = 1000\n\n    # -----------------------------------------------------------------\n    # Constructors\n\n    _dtype: np.dtype[np.datetime64] | DatetimeTZDtype\n    _freq: BaseOffset | None = None\n\n    @classmethod\n    def _validate_dtype(cls, values, dtype):\n        # used in TimeLikeOps.__init__\n        dtype = _validate_dt64_dtype(dtype)\n        _validate_dt64_dtype(values.dtype)\n        if isinstance(dtype, np.dtype):\n            if values.dtype != dtype:\n                raise ValueError("Values resolution does not match dtype.")\n        else:\n            vunit = np.datetime_data(values.dtype)[0]\n            if vunit != dtype.unit:\n                raise ValueError("Values resolution does not match dtype.")\n        return dtype\n\n    # error: Signature of "_simple_new" incompatible with supertype "NDArrayBacked"\n    @classmethod\n    def _simple_new(  # type: ignore[override]\n        cls,\n        values: npt.NDArray[np.datetime64],\n        freq: BaseOffset | None = None,\n        dtype: np.dtype[np.datetime64] | DatetimeTZDtype = DT64NS_DTYPE,\n    ) -> Self:\n        assert isinstance(values, np.ndarray)\n        assert dtype.kind == "M"\n        if isinstance(dtype, np.dtype):\n            assert dtype == values.dtype\n            assert not is_unitless(dtype)\n        else:\n            # DatetimeTZDtype. If we have e.g. DatetimeTZDtype[us, UTC],\n            #  then values.dtype should be M8[us].\n            assert dtype._creso == get_unit_from_dtype(values.dtype)\n\n        result = super()._simple_new(values, dtype)\n        result._freq = freq\n        return result\n\n    @classmethod\n    def _from_sequence(cls, scalars, *, dtype=None, copy: bool = False) -> Self:\n        return cls._from_sequence_not_strict(scalars, dtype=dtype, copy=copy)\n\n    @classmethod\n    def _from_sequence_not_strict(\n        cls,\n        data,\n        *,\n        dtype=None,\n        copy: bool = False,\n        tz=lib.no_default,\n        freq: str | BaseOffset | lib.NoDefault | None = lib.no_default,\n        dayfirst: bool = False,\n        yearfirst: bool = False,\n        ambiguous: TimeAmbiguous = "raise",\n    ) -> Self:\n        """\n        A non-strict version of _from_sequence, called from DatetimeIndex.__new__.\n        """\n\n        # if the user either explicitly passes tz=None or a tz-naive dtype, we\n        #  disallow inferring a tz.\n        explicit_tz_none = tz is None\n        if tz is lib.no_default:\n            tz = None\n        else:\n            tz = timezones.maybe_get_tz(tz)\n\n        dtype = _validate_dt64_dtype(dtype)\n        # if dtype has an embedded tz, capture it\n        tz = _validate_tz_from_dtype(dtype, tz, explicit_tz_none)\n\n        unit = None\n        if dtype is not None:\n            unit = dtl.dtype_to_unit(dtype)\n\n        data, copy = dtl.ensure_arraylike_for_datetimelike(\n            data, copy, cls_name="DatetimeArray"\n        )\n        inferred_freq = None\n        if isinstance(data, DatetimeArray):\n            inferred_freq = data.freq\n\n        subarr, tz = _sequence_to_dt64(\n            data,\n            copy=copy,\n            tz=tz,\n            dayfirst=dayfirst,\n            yearfirst=yearfirst,\n            ambiguous=ambiguous,\n            out_unit=unit,\n        )\n        # We have to call this again after possibly inferring a tz above\n        _validate_tz_from_dtype(dtype, tz, explicit_tz_none)\n        if tz is not None and explicit_tz_none:\n            raise ValueError(\n                "Passed data is timezone-aware, incompatible with \'tz=None\'. "\n                "Use obj.tz_localize(None) instead."\n            )\n\n        data_unit = np.datetime_data(subarr.dtype)[0]\n        data_unit = cast("TimeUnit", data_unit)\n        data_dtype = tz_to_dtype(tz, data_unit)\n        result = cls._simple_new(subarr, freq=inferred_freq, dtype=data_dtype)\n        if unit is not None and unit != result.unit:\n            # If unit was specified in user-passed dtype, cast to it here\n            # error: Argument 1 to "as_unit" of "TimelikeOps" has\n            # incompatible type "str"; expected "Literal[\'s\', \'ms\', \'us\', \'ns\']"\n            # [arg-type]\n            result = result.as_unit(unit)  # type: ignore[arg-type]\n\n        validate_kwds = {"ambiguous": ambiguous}\n        result._maybe_pin_freq(freq, validate_kwds)\n        return result\n\n    @classmethod\n    def _generate_range(\n        cls,\n        start,\n        end,\n        periods: int | None,\n        freq,\n        tz=None,\n        normalize: bool = False,\n        ambiguous: TimeAmbiguous = "raise",\n        nonexistent: TimeNonexistent = "raise",\n        inclusive: IntervalClosedType = "both",\n        *,\n        unit: TimeUnit = "ns",\n    ) -> Self:\n        periods = dtl.validate_periods(periods)\n        if freq is None and any(x is None for x in [periods, start, end]):\n            raise ValueError("Must provide freq argument if no data is supplied")\n\n        if com.count_not_none(start, end, periods, freq) != 3:\n            raise ValueError(\n                "Of the four parameters: start, end, periods, "\n                "and freq, exactly three must be specified"\n            )\n        freq = to_offset(freq)\n\n        if start is not None:\n            start = Timestamp(start)\n\n        if end is not None:\n            end = Timestamp(end)\n\n        if start is NaT or end is NaT:\n            raise ValueError("Neither `start` nor `end` can be NaT")\n\n        if unit is not None:\n            if unit not in ["s", "ms", "us", "ns"]:\n                raise ValueError("\'unit\' must be one of \'s\', \'ms\', \'us\', \'ns\'")\n        else:\n            unit = "ns"\n\n        if start is not None:\n            start = start.as_unit(unit, round_ok=False)\n        if end is not None:\n            end = end.as_unit(unit, round_ok=False)\n\n        left_inclusive, right_inclusive = validate_inclusive(inclusive)\n        start, end = _maybe_normalize_endpoints(start, end, normalize)\n        tz = _infer_tz_from_endpoints(start, end, tz)\n\n        if tz is not None:\n            # Localize the start and end arguments\n            start = _maybe_localize_point(start, freq, tz, ambiguous, nonexistent)\n            end = _maybe_localize_point(end, freq, tz, ambiguous, nonexistent)\n\n        if freq is not None:\n            # Offset handling:\n            # Ticks (fixed-duration like hours/minutes): keep tz; do absolute-time math.\n            # Other calendar offsets: drop tz; do naive wall time; localize once later\n            # so `ambiguous`/`nonexistent` are applied correctly.\n            if not isinstance(freq, Tick):\n                if start is not None and start.tz is not None:\n                    start = start.tz_localize(None)\n                if end is not None and end.tz is not None:\n                    end = end.tz_localize(None)\n\n            if isinstance(freq, (Tick, Day)):\n                i8values = generate_regular_range(start, end, periods, freq, unit=unit)\n            elif freq.n >= 1 and freq._supports_daily_offset_mask:\n                # GH#16463: fast "daily range + filter" path for offsets\n                # that support vectorized on-offset checks.\n                try:\n                    i8values = generate_daily_offset_range(\n                        start, end, periods, freq, unit=unit\n                    )\n                except (OutOfBoundsDatetime, OutOfBoundsTimedelta, OverflowError):\n                    # Near Timestamp bounds with periods; the iterative\n                    # path handles this by stopping before overflow.\n                    xdr = _generate_range(\n                        start=start,\n                        end=end,\n                        periods=periods,\n                        offset=freq,\n                        unit=unit,\n                    )\n                    i8values = np.array([x._value for x in xdr], dtype=np.int64)\n            else:\n                xdr = _generate_range(\n                    start=start,\n                    end=end,\n                    periods=periods,\n                    offset=freq,\n                    unit=unit,\n                )\n                i8values = np.array([x._value for x in xdr], dtype=np.int64)\n\n            endpoint_tz = start.tz if start is not None else end.tz\n\n            if tz is not None and endpoint_tz is None:\n                if not timezones.is_utc(tz):\n                    # short-circuit tz_localize_to_utc which would make\n                    #  an unnecessary copy with UTC but be a no-op.\n                    creso = abbrev_to_npy_unit(unit)\n                    i8values = tzconversion.tz_localize_to_utc(\n                        i8values,\n                        tz,\n                        ambiguous=ambiguous,\n                        nonexistent=nonexistent,\n                        creso=creso,\n                    )\n\n                # i8values is localized datetime64 array -> have to convert\n                # start/end as well to compare\n                if start is not None:\n                    start = start.tz_localize(tz, ambiguous, nonexistent)\n                if end is not None:\n                    end = end.tz_localize(tz, ambiguous, nonexistent)\n        else:\n            # Create a linearly spaced date_range in local time\n            # Nanosecond-granularity timestamps aren\'t always correctly\n            # representable with doubles, so we limit the range that we\n            # pass to np.linspace as much as possible\n            periods = cast("int", periods)\n            i8values = (\n                np.linspace(0, end._value - start._value, periods, dtype="int64")\n                + start._value\n            )\n            if i8values.dtype != "i8":\n                # 2022-01-09 I (brock) am not sure if it is possible for this\n                #  to overflow and cast to e.g. f8, but if it does we need to cast\n                i8values = i8values.astype("i8")\n\n        if start == end:\n            if not left_inclusive and not right_inclusive:\n                i8values = i8values[1:-1]\n        else:\n            start_i8 = Timestamp(start)._value\n            end_i8 = Timestamp(end)._value\n            if not left_inclusive or not right_inclusive:\n                if not left_inclusive and len(i8values) and i8values[0] == start_i8:\n                    i8values = i8values[1:]\n                if not right_inclusive and len(i8values) and i8values[-1] == end_i8:\n                    i8values = i8values[:-1]\n\n        dt64_values = i8values.view(f"datetime64[{unit}]")\n        dtype = tz_to_dtype(tz, unit=unit)\n        return cls._simple_new(dt64_values, freq=freq, dtype=dtype)\n\n    # -----------------------------------------------------------------\n    # DatetimeLike Interface\n\n    def _unbox_scalar(self, value) -> np.datetime64:\n        if not isinstance(value, self._scalar_type) and value is not NaT:\n            raise ValueError("\'value\' should be a Timestamp.")\n        self._check_compatible_with(value)\n        if value is NaT:\n            return np.datetime64(value._value, self.unit)\n        else:\n            return value.as_unit(self.unit, round_ok=False).asm8\n\n    def _scalar_from_string(self, value) -> Timestamp | NaTType:\n        return Timestamp(value, tz=self.tz)\n\n    def _check_compatible_with(self, other) -> None:\n        if other is NaT:\n            return\n        self._assert_tzawareness_compat(other)\n\n    # -----------------------------------------------------------------\n    # Descriptive Properties\n\n    def _box_func(self, x: np.datetime64) -> Timestamp | NaTType:\n        # GH#42228\n        value = x.view("i8")\n        ts = Timestamp._from_value_and_reso(value, reso=self._creso, tz=self.tz)\n        return ts\n\n    @property\n    # error: Return type "Union[dtype, DatetimeTZDtype]" of "dtype"\n    # incompatible with return type "ExtensionDtype" in supertype\n    # "ExtensionArray"\n    def dtype(self) -> np.dtype[np.datetime64] | DatetimeTZDtype:  # type: ignore[override]\n        """\n        The dtype for the DatetimeArray.\n\n        .. warning::\n\n           A future version of pandas will change dtype to never be a\n           ``numpy.dtype``. Instead, :attr:`DatetimeArray.dtype` will\n           always be an instance of an ``ExtensionDtype`` subclass.\n\n        Returns\n        -------\n        numpy.dtype or DatetimeTZDtype\n            If the values are tz-naive, then ``np.dtype(\'datetime64[ns]\')``\n            is returned.\n\n            If the values are tz-aware, then the ``DatetimeTZDtype``\n            is returned.\n        """\n        return self._dtype\n\n    @property\n    def tz(self) -> tzinfo | None:\n        """\n        Return the timezone.\n\n        This property returns the timezone information associated with the\n        datetime data. If the data is timezone-naive (i.e. has no timezone\n        information), it returns None.\n\n        Returns\n        -------\n        zoneinfo.ZoneInfo, datetime.tzinfo, pytz.tzinfo.BaseTZInfo, dateutil.tz.tz.tzfile, or None\n            Returns None when the array is tz-naive.\n\n        See Also\n        --------\n        DatetimeIndex.tz_localize : Localize tz-naive DatetimeIndex to a\n            given time zone, or remove timezone from a tz-aware DatetimeIndex.\n        DatetimeIndex.tz_convert : Convert tz-aware DatetimeIndex from\n            one time zone to another.\n\n        Examples\n        --------\n        For Series:\n\n        >>> s = pd.Series(["1/1/2020 10:00:00+00:00", "2/1/2020 11:00:00+00:00"])\n        >>> s = pd.to_datetime(s)\n        >>> s\n        0   2020-01-01 10:00:00+00:00\n        1   2020-02-01 11:00:00+00:00\n        dtype: datetime64[us, UTC]\n        >>> s.dt.tz\n        datetime.timezone.utc\n\n        For DatetimeIndex:\n\n        >>> idx = pd.DatetimeIndex(\n        ...     ["1/1/2020 10:00:00+00:00", "2/1/2020 11:00:00+00:00"]\n        ... )\n        >>> idx.tz\n        datetime.timezone.utc\n        """  # noqa: E501\n        # GH 18595\n        return getattr(self.dtype, "tz", None)\n\n    @tz.setter\n    def tz(self, value):\n        # GH 3746: Prevent localizing or converting the index by setting tz\n        raise AttributeError(\n            "Cannot directly set timezone. Use tz_localize() "\n            "or tz_convert() as appropriate"\n        )\n\n    @property\n    def tzinfo(self) -> tzinfo | None:\n        """\n        Alias for tz attribute\n        """\n        return self.tz\n\n    @property  # NB: override with cache_readonly in immutable subclasses\n    def is_normalized(self) -> bool:\n        """\n        Returns True if all of the dates are at midnight ("no time")\n        """\n        return is_date_array_normalized(self.asi8, self.tz, reso=self._creso)\n\n    @property  # NB: override with cache_readonly in immutable subclasses\n    def _resolution_obj(self) -> Resolution:\n        return get_resolution(self.asi8, self.tz, reso=self._creso)\n\n    # ----------------------------------------------------------------\n    # Array-Like / EA-Interface Methods\n\n    def __array__(self, dtype=None, copy=None) -> np.ndarray:\n        if dtype is None and self.tz:\n            # The default for tz-aware is object, to preserve tz info\n            dtype = object\n\n        return super().__array__(dtype=dtype, copy=copy)\n\n    def __iter__(self) -> Iterator:\n        """\n        Return an iterator over the boxed values\n\n        Yields\n        ------\n        tstamp : Timestamp\n        """\n        if self.ndim > 1:\n            for i in range(len(self)):\n                yield self[i]\n        else:\n            # convert in chunks of 10k for efficiency\n            data = self.asi8\n            length = len(self)\n            chunksize = _ITER_CHUNKSIZE\n            chunks = (length // chunksize) + 1\n\n            for i in range(chunks):\n                start_i = i * chunksize\n                end_i = min((i + 1) * chunksize, length)\n                converted = ints_to_pydatetime(\n                    data[start_i:end_i],\n                    tz=self.tz,\n                    box="timestamp",\n                    reso=self._creso,\n                )\n                yield from converted\n\n    def astype(self, dtype, copy: bool = True):\n        # We handle\n        #   --> datetime\n        #   --> period\n        # DatetimeLikeArrayMixin Super handles the rest.\n        dtype = pandas_dtype(dtype)\n\n        if dtype == self.dtype:\n            if copy:\n                return self.copy()\n            return self\n\n        elif isinstance(dtype, ExtensionDtype):\n            if not isinstance(dtype, DatetimeTZDtype):\n                # e.g. Sparse[datetime64[ns]]\n                return super().astype(dtype, copy=copy)\n            elif self.tz is None:\n                # pre-2.0 this did self.tz_localize(dtype.tz), which did not match\n                #  the Series behavior which did\n                #  values.tz_localize("UTC").tz_convert(dtype.tz)\n                raise TypeError(\n                    "Cannot use .astype to convert from timezone-naive dtype to "\n                    "timezone-aware dtype. Use obj.tz_localize instead or "\n                    "series.dt.tz_localize instead"\n                )\n            else:\n                # tzaware unit conversion e.g. datetime64[s, UTC]\n                np_dtype = np.dtype(dtype.str)\n                res_values = astype_overflowsafe(self._ndarray, np_dtype, copy=copy)\n                return type(self)._simple_new(res_values, dtype=dtype, freq=self.freq)\n\n        elif (\n            self.tz is None\n            and lib.is_np_dtype(dtype, "M")\n            and not is_unitless(dtype)\n            and is_supported_dtype(dtype)\n        ):\n            # unit conversion e.g. datetime64[s]\n            res_values = astype_overflowsafe(self._ndarray, dtype, copy=True)\n            return type(self)._simple_new(res_values, dtype=res_values.dtype)\n            # TODO: preserve freq?\n\n        elif self.tz is not None and lib.is_np_dtype(dtype, "M"):\n            # pre-2.0 behavior for DTA/DTI was\n            #  values.tz_convert("UTC").tz_localize(None), which did not match\n            #  the Series behavior\n            raise TypeError(\n                "Cannot use .astype to convert from timezone-aware dtype to "\n                "timezone-naive dtype. Use obj.tz_localize(None) or "\n                "obj.tz_convert(\'UTC\').tz_localize(None) instead."\n            )\n\n        elif (\n            self.tz is None\n            and lib.is_np_dtype(dtype, "M")\n            and dtype != self.dtype\n            and is_unitless(dtype)\n        ):\n            raise TypeError(\n                "Casting to unit-less dtype \'datetime64\' is not supported. "\n                "Pass e.g. \'datetime64[ns]\' instead."\n            )\n\n        elif isinstance(dtype, PeriodDtype):\n            return self.to_period(freq=dtype.freq)\n        return dtl.DatetimeLikeArrayMixin.astype(self, dtype, copy)\n\n    # -----------------------------------------------------------------\n    # Rendering Methods\n\n    def _format_native_types(\n        self, *, na_rep: str | float = "NaT", date_format=None, **kwargs\n    ) -> npt.NDArray[np.object_]:\n        if date_format is None and self._is_dates_only:\n            # Only dates and no timezone: provide a default format\n            date_format = "%Y-%m-%d"\n\n        return tslib.format_array_from_datetime(\n            self.asi8, tz=self.tz, format=date_format, na_rep=na_rep, reso=self._creso\n        )\n\n    # -----------------------------------------------------------------\n    # Comparison Methods\n\n    def _assert_tzawareness_compat(self, other) -> None:\n        # adapted from _Timestamp._assert_tzawareness_compat\n        other_tz = getattr(other, "tzinfo", None)\n        other_dtype = getattr(other, "dtype", None)\n\n        if isinstance(other_dtype, DatetimeTZDtype):\n            # Get tzinfo from Series dtype\n            other_tz = other.dtype.tz\n        if other is NaT:\n            # pd.NaT quacks both aware and naive\n            pass\n        elif self.tz is None:\n            if other_tz is not None:\n                raise TypeError(\n                    "Cannot compare tz-naive and tz-aware datetime-like objects."\n                )\n        elif other_tz is None:\n            raise TypeError(\n                "Cannot compare tz-naive and tz-aware datetime-like objects"\n            )\n\n    # -----------------------------------------------------------------\n    # Arithmetic Methods\n\n    def _add_offset(self, offset: BaseOffset) -> Self:\n        assert not isinstance(offset, Tick)\n\n        # For pure-timedelta DateOffset with tz-aware data, add to UTC values\n        # directly to avoid nonexistent/ambiguous time errors from\n        # re-localizing wall-time results near DST (GH#28610).\n        if (\n            self.tz is not None\n            and isinstance(offset, RelativeDeltaOffset)\n            and not offset._use_relativedelta\n        ):\n            res_values = self._ndarray + offset._pd_timedelta\n            result = type(self)._simple_new(res_values, dtype=self.dtype)\n            if offset.normalize:\n                result = result.normalize()\n                result._freq = None\n            return result\n\n        if self.tz is not None:\n            values = self.tz_localize(None)\n        else:\n            values = self\n\n        try:\n            res_values = offset._apply_array(values._ndarray)\n            if res_values.dtype.kind == "i":\n                res_values = res_values.view(values.dtype)\n        except NotImplementedError:\n            if get_option("performance_warnings"):\n                warnings.warn(\n                    "Non-vectorized DateOffset being applied to Series or "\n                    "DatetimeIndex.",\n                    PerformanceWarning,\n                    stacklevel=find_stack_level(),\n                )\n            res_values = self.astype("O") + offset\n            result = type(self)._from_sequence(res_values, dtype=self.dtype)\n\n        else:\n            result = type(self)._simple_new(res_values, dtype=res_values.dtype)\n            if offset.normalize:\n                result = result.normalize()\n                result._freq = None\n\n            if self.tz is not None:\n                result = result.tz_localize(self.tz)\n\n        return result\n\n    # -----------------------------------------------------------------\n    # Timezone Conversion and Localization Methods\n\n    def _local_timestamps(self) -> npt.NDArray[np.int64]:\n        """\n        Convert to an i8 (unix-like nanosecond timestamp) representation\n        while keeping the local timezone and not using UTC.\n        This is used to calculate time-of-day information as if the timestamps\n        were timezone-naive.\n        """\n        if self.tz is None or timezones.is_utc(self.tz):\n            # Avoid the copy that would be made in tzconversion\n            return self.asi8\n        return tz_convert_from_utc(self.asi8, self.tz, reso=self._creso)\n\n    def tz_convert(self, tz) -> Self:\n        """\n        Convert tz-aware Datetime Array/Index from one time zone to another.\n\n        This method converts datetime values from their current timezone to a\n        different timezone. The underlying UTC time remains the same, only the\n        local time representation changes to reflect the target timezone.\n\n        Parameters\n        ----------\n        tz : str, zoneinfo.ZoneInfo, pytz.timezone, dateutil.tz.tzfile, datetime.tzinfo or None\n            Time zone for time. Corresponding timestamps would be converted\n            to this time zone of the Datetime Array/Index. A `tz` of None will\n            convert to UTC and remove the timezone information.\n\n        Returns\n        -------\n        Array or Index\n            Datetime Array/Index with target `tz`.\n\n        Raises\n        ------\n        TypeError\n            If Datetime Array/Index is tz-naive.\n\n        See Also\n        --------\n        DatetimeIndex.tz : A timezone that has a variable offset from UTC.\n        DatetimeIndex.tz_localize : Localize tz-naive DatetimeIndex to a\n            given time zone, or remove timezone from a tz-aware DatetimeIndex.\n\n        Examples\n        --------\n        With the `tz` parameter, we can change the DatetimeIndex\n        to other time zones:\n\n        >>> dti = pd.date_range(\n        ...     start="2014-08-01 09:00", freq="h", periods=3, tz="Europe/Berlin"\n        ... )\n\n        >>> dti\n        DatetimeIndex([\'2014-08-01 09:00:00+02:00\',\n                       \'2014-08-01 10:00:00+02:00\',\n                       \'2014-08-01 11:00:00+02:00\'],\n                      dtype=\'datetime64[us, Europe/Berlin]\', freq=\'h\')\n\n        >>> dti.tz_convert("US/Central")\n        DatetimeIndex([\'2014-08-01 02:00:00-05:00\',\n                       \'2014-08-01 03:00:00-05:00\',\n                       \'2014-08-01 04:00:00-05:00\'],\n                      dtype=\'datetime64[us, US/Central]\', freq=\'h\')\n\n        With the ``tz=None``, we can remove the timezone (after converting\n        to UTC if necessary):\n\n        >>> dti = pd.date_range(\n        ...     start="2014-08-01 09:00", freq="h", periods=3, tz="Europe/Berlin"\n        ... )\n\n        >>> dti\n        DatetimeIndex([\'2014-08-01 09:00:00+02:00\',\n                       \'2014-08-01 10:00:00+02:00\',\n                       \'2014-08-01 11:00:00+02:00\'],\n                        dtype=\'datetime64[us, Europe/Berlin]\', freq=\'h\')\n\n        >>> dti.tz_convert(None)\n        DatetimeIndex([\'2014-08-01 07:00:00\',\n                       \'2014-08-01 08:00:00\',\n                       \'2014-08-01 09:00:00\'],\n                        dtype=\'datetime64[us]\', freq=\'h\')\n        """  # noqa: E501\n        tz = timezones.maybe_get_tz(tz)\n\n        if self.tz is None:\n            # tz naive, use tz_localize\n            raise TypeError(\n                "Cannot convert tz-naive timestamps, use tz_localize to localize"\n            )\n\n        # No conversion since timestamps are all UTC to begin with\n        dtype = tz_to_dtype(tz, unit=self.unit)\n        new_freq = None\n        if isinstance(self.freq, Tick):\n            new_freq = self.freq\n        return self._simple_new(self._ndarray, dtype=dtype, freq=new_freq)\n\n    @dtl.ravel_compat\n    def tz_localize(\n        self,\n        tz,\n        ambiguous: TimeAmbiguous = "raise",\n        nonexistent: TimeNonexistent = "raise",\n    ) -> Self:\n        """\n        Localize tz-naive Datetime Array/Index to tz-aware Datetime Array/Index.\n\n        This method takes a time zone (tz) naive Datetime Array/Index object\n        and makes this time zone aware. It does not move the time to another\n        time zone.\n\n        This method can also be used to do the inverse -- to create a time\n        zone unaware object from an aware object. To that end, pass `tz=None`.\n\n        Parameters\n        ----------\n        tz : str, zoneinfo.ZoneInfo, pytz.timezone, dateutil.tz.tzfile, datetime.tzinfo or None\n            Time zone to convert timestamps to. Passing ``None`` will\n            remove the time zone information preserving local time.\n        ambiguous : \'infer\', \'NaT\', bool array, default \'raise\'\n            When clocks moved backward due to DST, ambiguous times may arise.\n            For example in Central European Time (UTC+01), when going from\n            03:00 DST to 02:00 non-DST, 02:30:00 local time occurs both at\n            00:30:00 UTC and at 01:30:00 UTC. In such a situation, the\n            `ambiguous` parameter dictates how ambiguous times should be\n            handled.\n\n            - \'infer\' will attempt to infer fall dst-transition hours based on\n              order\n            - bool-ndarray where True signifies a DST time, False signifies a\n              non-DST time (note that this flag is only applicable for\n              ambiguous times)\n            - \'NaT\' will return NaT where there are ambiguous times\n            - \'raise\' will raise a ValueError if there are ambiguous\n              times.\n\n        nonexistent : \'shift_forward\', \'shift_backward\', \'NaT\', timedelta, \\\ndefault \'raise\'\n            A nonexistent time does not exist in a particular timezone\n            where clocks moved forward due to DST.\n\n            - \'shift_forward\' will shift the nonexistent time forward to the\n              closest existing time\n            - \'shift_backward\' will shift the nonexistent time backward to the\n              closest existing time\n            - \'NaT\' will return NaT where there are nonexistent times\n            - timedelta objects will shift nonexistent times by the timedelta\n            - \'raise\' will raise a ValueError if there are\n              nonexistent times.\n\n        Returns\n        -------\n        Same type as self\n            Array/Index converted to the specified time zone.\n\n        Raises\n        ------\n        TypeError\n            If the Datetime Array/Index is tz-aware and tz is not None.\n\n        See Also\n        --------\n        DatetimeIndex.tz_convert : Convert tz-aware DatetimeIndex from\n            one time zone to another.\n\n        Examples\n        --------\n        >>> tz_naive = pd.date_range(\'2018-03-01 09:00\', periods=3)\n        >>> tz_naive\n        DatetimeIndex([\'2018-03-01 09:00:00\', \'2018-03-02 09:00:00\',\n                       \'2018-03-03 09:00:00\'],\n                      dtype=\'datetime64[us]\', freq=\'D\')\n\n        Localize DatetimeIndex in US/Eastern time zone:\n\n        >>> tz_aware = tz_naive.tz_localize(tz=\'US/Eastern\')\n        >>> tz_aware\n        DatetimeIndex([\'2018-03-01 09:00:00-05:00\',\n                       \'2018-03-02 09:00:00-05:00\',\n                       \'2018-03-03 09:00:00-05:00\'],\n                      dtype=\'datetime64[us, US/Eastern]\', freq=None)\n\n        With the ``tz=None``, we can remove the time zone information\n        while keeping the local time (not converted to UTC):\n\n        >>> tz_aware.tz_localize(None)\n        DatetimeIndex([\'2018-03-01 09:00:00\', \'2018-03-02 09:00:00\',\n                       \'2018-03-03 09:00:00\'],\n                      dtype=\'datetime64[us]\', freq=None)\n\n        Be careful with DST changes. When there is sequential data, pandas can\n        infer the DST time:\n\n        >>> s = pd.to_datetime(pd.Series([\'2018-10-28 01:30:00\',\n        ...                               \'2018-10-28 02:00:00\',\n        ...                               \'2018-10-28 02:30:00\',\n        ...                               \'2018-10-28 02:00:00\',\n        ...                               \'2018-10-28 02:30:00\',\n        ...                               \'2018-10-28 03:00:00\',\n        ...                               \'2018-10-28 03:30:00\']))\n        >>> s.dt.tz_localize(\'CET\', ambiguous=\'infer\')\n        0   2018-10-28 01:30:00+02:00\n        1   2018-10-28 02:00:00+02:00\n        2   2018-10-28 02:30:00+02:00\n        3   2018-10-28 02:00:00+01:00\n        4   2018-10-28 02:30:00+01:00\n        5   2018-10-28 03:00:00+01:00\n        6   2018-10-28 03:30:00+01:00\n        dtype: datetime64[us, CET]\n\n        In some cases, inferring the DST is impossible. In such cases, you can\n        pass an ndarray to the ambiguous parameter to set the DST explicitly\n\n        >>> s = pd.to_datetime(pd.Series([\'2018-10-28 01:20:00\',\n        ...                               \'2018-10-28 02:36:00\',\n        ...                               \'2018-10-28 03:46:00\']))\n        >>> s.dt.tz_localize(\'CET\', ambiguous=np.array([True, True, False]))\n        0   2018-10-28 01:20:00+02:00\n        1   2018-10-28 02:36:00+02:00\n        2   2018-10-28 03:46:00+01:00\n        dtype: datetime64[us, CET]\n\n        If the DST transition causes nonexistent times, you can shift these\n        dates forward or backwards with a timedelta object or `\'shift_forward\'`\n        or `\'shift_backward\'`.\n\n        >>> s = pd.to_datetime(pd.Series([\'2015-03-29 02:30:00\',\n        ...                               \'2015-03-29 03:30:00\'], dtype="M8[ns]"))\n        >>> s.dt.tz_localize(\'Europe/Warsaw\', nonexistent=\'shift_forward\')\n        0   2015-03-29 03:00:00+02:00\n        1   2015-03-29 03:30:00+02:00\n        dtype: datetime64[ns, Europe/Warsaw]\n\n        >>> s.dt.tz_localize(\'Europe/Warsaw\', nonexistent=\'shift_backward\')\n        0   2015-03-29 01:59:59.999999999+01:00\n        1   2015-03-29 03:30:00+02:00\n        dtype: datetime64[ns, Europe/Warsaw]\n\n        >>> s.dt.tz_localize(\'Europe/Warsaw\', nonexistent=pd.Timedelta(\'1h\'))\n        0   2015-03-29 03:30:00+02:00\n        1   2015-03-29 03:30:00+02:00\n        dtype: datetime64[ns, Europe/Warsaw]\n        """  # noqa: E501\n        nonexistent_options = ("raise", "NaT", "shift_forward", "shift_backward")\n        if nonexistent not in nonexistent_options and not isinstance(\n            nonexistent, timedelta\n        ):\n            raise ValueError(\n                "The nonexistent argument must be one of \'raise\', "\n                "\'NaT\', \'shift_forward\', \'shift_backward\' or "\n                "a timedelta object"\n            )\n\n        if self.tz is not None:\n            if tz is None:\n                new_dates = tz_convert_from_utc(self.asi8, self.tz, reso=self._creso)\n            else:\n                raise TypeError("Already tz-aware, use tz_convert to convert.")\n        else:\n            tz = timezones.maybe_get_tz(tz)\n            # Convert to UTC\n\n            new_dates = tzconversion.tz_localize_to_utc(\n                self.asi8,\n                tz,\n                ambiguous=ambiguous,\n                nonexistent=nonexistent,\n                creso=self._creso,\n            )\n        new_dates_dt64 = new_dates.view(f"M8[{self.unit}]")\n        dtype = tz_to_dtype(tz, unit=self.unit)\n\n        freq = None\n        if timezones.is_utc(tz) or (len(self) == 1 and not isna(new_dates_dt64[0])):\n            # we can preserve freq\n            # TODO: Also for fixed-offsets\n            freq = self.freq\n        elif tz is None and self.tz is None:\n            # no-op\n            freq = self.freq\n        return self._simple_new(new_dates_dt64, dtype=dtype, freq=freq)\n\n    # ----------------------------------------------------------------\n    # Conversion Methods - Vectorized analogues of Timestamp methods\n\n    def to_pydatetime(self) -> npt.NDArray[np.object_]:\n        """\n        Return an ndarray of ``datetime.datetime`` objects.\n\n        This method converts each element in the DatetimeArray to a native\n        Python ``datetime.datetime`` object, including timezone information\n        if present.\n\n        Returns\n        -------\n        numpy.ndarray\n            An ndarray of ``datetime.datetime`` objects.\n\n        See Also\n        --------\n        DatetimeIndex.to_julian_date : Converts Datetime Array to float64 ndarray\n            of Julian Dates.\n\n        Examples\n        --------\n        >>> idx = pd.date_range("2018-02-27", periods=3)\n        >>> idx.to_pydatetime()\n        array([datetime.datetime(2018, 2, 27, 0, 0),\n               datetime.datetime(2018, 2, 28, 0, 0),\n               datetime.datetime(2018, 3, 1, 0, 0)], dtype=object)\n        """\n        return ints_to_pydatetime(self.asi8, tz=self.tz, reso=self._creso)\n\n    def normalize(self) -> Self:\n        """\n        Convert times to midnight.\n\n        The time component of the date-time is converted to midnight i.e.\n        00:00:00. This is useful in cases, when the time does not matter.\n        Length is unaltered. The timezones are unaffected.\n\n        This method is available on Series with datetime values under\n        the ``.dt`` accessor, and directly on Datetime Array/Index.\n\n        Returns\n        -------\n        DatetimeArray, DatetimeIndex or Series\n            The same type as the original data. Series will have the same\n            name and index. DatetimeIndex will have the same name.\n\n        See Also\n        --------\n        floor : Floor the datetimes to the specified freq.\n        ceil : Ceil the datetimes to the specified freq.\n        round : Round the datetimes to the specified freq.\n\n        Examples\n        --------\n        >>> idx = pd.date_range(\n        ...     start="2014-08-01 10:00", freq="h", periods=3, tz="Asia/Calcutta"\n        ... )\n        >>> idx\n        DatetimeIndex([\'2014-08-01 10:00:00+05:30\',\n                       \'2014-08-01 11:00:00+05:30\',\n                       \'2014-08-01 12:00:00+05:30\'],\n                        dtype=\'datetime64[us, Asia/Calcutta]\', freq=\'h\')\n        >>> idx.normalize()\n        DatetimeIndex([\'2014-08-01 00:00:00+05:30\',\n                       \'2014-08-01 00:00:00+05:30\',\n                       \'2014-08-01 00:00:00+05:30\'],\n                       dtype=\'datetime64[us, Asia/Calcutta]\', freq=None)\n        """\n        new_values = normalize_i8_timestamps(self.asi8, self.tz, reso=self._creso)\n        dt64_values = new_values.view(self._ndarray.dtype)\n\n        dta = type(self)._simple_new(dt64_values, dtype=dt64_values.dtype)\n        dta = dta._with_freq("infer")\n        if self.tz is not None:\n            dta = dta.tz_localize(self.tz)\n        return dta\n\n    def to_period(self, freq=None) -> PeriodArray:\n        """\n        Cast to PeriodArray/PeriodIndex at a particular frequency.\n\n        Converts DatetimeArray/Index to PeriodArray/PeriodIndex.\n\n        Parameters\n        ----------\n        freq : str or Period, optional\n            One of pandas\' :ref:`period aliases <timeseries.period_aliases>`\n            or a Period object. Will be inferred by default.\n\n        Returns\n        -------\n        PeriodArray/PeriodIndex\n            Immutable ndarray holding ordinal values at a particular frequency.\n\n        Raises\n        ------\n        ValueError\n            When converting a DatetimeArray/Index with non-regular values,\n            so that a frequency cannot be inferred.\n\n        See Also\n        --------\n        PeriodIndex: Immutable ndarray holding ordinal values.\n        DatetimeIndex.to_pydatetime: Return DatetimeIndex as object.\n\n        Examples\n        --------\n        >>> df = pd.DataFrame(\n        ...     {"y": [1, 2, 3]},\n        ...     index=pd.to_datetime(\n        ...         [\n        ...             "2000-03-31 00:00:00",\n        ...             "2000-05-31 00:00:00",\n        ...             "2000-08-31 00:00:00",\n        ...         ]\n        ...     ),\n        ... )\n        >>> df.index.to_period("M")\n        PeriodIndex([\'2000-03\', \'2000-05\', \'2000-08\'],\n                    dtype=\'period[M]\')\n\n        Infer the daily frequency\n\n        >>> idx = pd.date_range("2017-01-01", periods=2)\n        >>> idx.to_period()\n        PeriodIndex([\'2017-01-01\', \'2017-01-02\'],\n                    dtype=\'period[D]\')\n        """\n        from pandas.core.arrays import PeriodArray\n\n        if self.tz is not None:\n            warnings.warn(\n                "Converting to PeriodArray/Index representation "\n                "will drop timezone information.",\n                UserWarning,\n                stacklevel=find_stack_level(),\n            )\n\n        if freq is None:\n            freq = self.freqstr or self.inferred_freq\n            if isinstance(self.freq, BaseOffset) and hasattr(\n                self.freq, "_period_dtype_code"\n            ):\n                freq = PeriodDtype(self.freq)._freqstr\n\n            if freq is None:\n                raise ValueError(\n                    "You must pass a freq argument as current index has none."\n                )\n\n            res = get_period_alias(freq)\n\n            #  https://github.com/pandas-dev/pandas/issues/33358\n            if res is None:\n                res = freq\n\n            freq = res\n        return PeriodArray._from_datetime64(self._ndarray, freq, tz=self.tz)\n\n    # -----------------------------------------------------------------\n    # Properties - Vectorized Timestamp Properties/Methods\n\n    def month_name(self, locale=None) -> npt.NDArray[np.object_]:\n        """\n        Return the month names with specified locale.\n\n        This method returns the full name of the month (e.g., "January", "February")\n        for each datetime value in the Series/Index. The names can be localized\n        to different languages using the locale parameter.\n\n        Parameters\n        ----------\n        locale : str, optional\n            Locale determining the language in which to return the month name.\n            Default is English locale (``\'en_US.utf8\'``). Use the command\n            ``locale -a`` on your terminal on Unix systems to find your locale\n            language code.\n\n        Returns\n        -------\n        Series or Index\n            Series or Index of month names.\n\n        See Also\n        --------\n        DatetimeIndex.day_name : Return the day names with specified locale.\n\n        Examples\n        --------\n        >>> s = pd.Series(pd.date_range(start="2018-01", freq="ME", periods=3))\n        >>> s\n        0   2018-01-31\n        1   2018-02-28\n        2   2018-03-31\n        dtype: datetime64[us]\n        >>> s.dt.month_name()\n        0     January\n        1    February\n        2       March\n        dtype: str\n\n        >>> idx = pd.date_range(start="2018-01", freq="ME", periods=3)\n        >>> idx\n        DatetimeIndex([\'2018-01-31\', \'2018-02-28\', \'2018-03-31\'],\n                      dtype=\'datetime64[us]\', freq=\'ME\')\n        >>> idx.month_name()\n        Index([\'January\', \'February\', \'March\'], dtype=\'str\')\n\n        Using the ``locale`` parameter you can set a different locale language,\n        for example: ``idx.month_name(locale=\'pt_BR.utf8\')`` will return month\n        names in Brazilian Portuguese language.\n\n        >>> idx = pd.date_range(start="2018-01", freq="ME", periods=3)\n        >>> idx\n        DatetimeIndex([\'2018-01-31\', \'2018-02-28\', \'2018-03-31\'],\n                      dtype=\'datetime64[us]\', freq=\'ME\')\n        >>> idx.month_name(locale="pt_BR.utf8")  # doctest: +SKIP\n        Index([\'Janeiro\', \'Fevereiro\', \'Março\'], dtype=\'str\')\n        """\n        values = self._local_timestamps()\n\n        result = fields.get_date_name_field(\n            values, "month_name", locale=locale, reso=self._creso\n        )\n        result = self._maybe_mask_results(result, fill_value=None)\n        if using_string_dtype():\n            from pandas import (\n                StringDtype,\n                array as pd_array,\n            )\n\n            return pd_array(result, dtype=StringDtype(na_value=np.nan))  # type: ignore[return-value]\n        return result\n\n    def day_name(self, locale=None) -> npt.NDArray[np.object_]:\n        """\n        Return the day names with specified locale.\n\n        This method returns the full name of the day of the week (e.g., "Monday",\n        "Tuesday") for each datetime value in the Series/Index. The names can be\n        localized to different languages using the locale parameter.\n\n        Parameters\n        ----------\n        locale : str, optional\n            Locale determining the language in which to return the day name.\n            Default is English locale (``\'en_US.utf8\'``). Use the command\n            ``locale -a`` on your terminal on Unix systems to find your locale\n            language code.\n\n        Returns\n        -------\n        Series or Index\n            Series or Index of day names.\n\n        See Also\n        --------\n        DatetimeIndex.month_name : Return the month names with specified locale.\n\n        Examples\n        --------\n        >>> s = pd.Series(pd.date_range(start="2018-01-01", freq="D", periods=3))\n        >>> s\n        0   2018-01-01\n        1   2018-01-02\n        2   2018-01-03\n        dtype: datetime64[us]\n        >>> s.dt.day_name()\n        0       Monday\n        1      Tuesday\n        2    Wednesday\n        dtype: str\n\n        >>> idx = pd.date_range(start="2018-01-01", freq="D", periods=3)\n        >>> idx\n        DatetimeIndex([\'2018-01-01\', \'2018-01-02\', \'2018-01-03\'],\n                      dtype=\'datetime64[us]\', freq=\'D\')\n        >>> idx.day_name()\n        Index([\'Monday\', \'Tuesday\', \'Wednesday\'], dtype=\'str\')\n\n        Using the ``locale`` parameter you can set a different locale language,\n        for example: ``idx.day_name(locale=\'pt_BR.utf8\')`` will return day\n        names in Brazilian Portuguese language.\n\n        >>> idx = pd.date_range(start="2018-01-01", freq="D", periods=3)\n        >>> idx\n        DatetimeIndex([\'2018-01-01\', \'2018-01-02\', \'2018-01-03\'],\n                      dtype=\'datetime64[us]\', freq=\'D\')\n        >>> idx.day_name(locale="pt_BR.utf8")  # doctest: +SKIP\n        Index([\'Segunda\', \'Terça\', \'Quarta\'], dtype=\'str\')\n        """\n        values = self._local_timestamps()\n\n        result = fields.get_date_name_field(\n            values, "day_name", locale=locale, reso=self._creso\n        )\n        result = self._maybe_mask_results(result, fill_value=None)\n        if using_string_dtype():\n            # TODO: no tests that check for dtype of result as of 2024-08-15\n            from pandas import (\n                StringDtype,\n                array as pd_array,\n            )\n\n            return pd_array(result, dtype=StringDtype(na_value=np.nan))  # type: ignore[return-value]\n        return result\n\n    @property\n    def time(self) -> npt.NDArray[np.object_]:\n        """\n        Returns numpy array of :class:`datetime.time` objects.\n\n        The time part of the Timestamps.\n\n        See Also\n        --------\n        DatetimeIndex.timetz : Returns numpy array of :class:`datetime.time`\n            objects with timezones. The time part of the Timestamps.\n        DatetimeIndex.date : Returns numpy array of python :class:`datetime.date`\n            objects. Namely, the date part of Timestamps without time and timezone\n            information.\n\n        Examples\n        --------\n        For Series:\n\n        >>> s = pd.Series(["1/1/2020 10:00:00+00:00", "2/1/2020 11:00:00+00:00"])\n        >>> s = pd.to_datetime(s)\n        >>> s\n        0   2020-01-01 10:00:00+00:00\n        1   2020-02-01 11:00:00+00:00\n        dtype: datetime64[us, UTC]\n        >>> s.dt.time\n        0    10:00:00\n        1    11:00:00\n        dtype: object\n\n        For DatetimeIndex:\n\n        >>> idx = pd.DatetimeIndex(\n        ...     ["1/1/2020 10:00:00+00:00", "2/1/2020 11:00:00+00:00"]\n        ... )\n        >>> idx.time\n        array([datetime.time(10, 0), datetime.time(11, 0)], dtype=object)\n        """\n        # If the Timestamps have a timezone that is not UTC,\n        # convert them into their i8 representation while\n        # keeping their timezone and not using UTC\n        timestamps = self._local_timestamps()\n\n        return ints_to_pydatetime(timestamps, box="time", reso=self._creso)\n\n    @property\n    def timetz(self) -> npt.NDArray[np.object_]:\n        """\n        Returns numpy array of :class:`datetime.time` objects with timezones.\n\n        The time part of the Timestamps.\n\n        See Also\n        --------\n        DatetimeIndex.time : Returns numpy array of :class:`datetime.time` objects.\n            The time part of the Timestamps.\n        DatetimeIndex.tz : Return the timezone.\n\n        Examples\n        --------\n        For Series:\n\n        >>> s = pd.Series(["1/1/2020 10:00:00+00:00", "2/1/2020 11:00:00+00:00"])\n        >>> s = pd.to_datetime(s)\n        >>> s\n        0   2020-01-01 10:00:00+00:00\n        1   2020-02-01 11:00:00+00:00\n        dtype: datetime64[us, UTC]\n        >>> s.dt.timetz\n        0    10:00:00+00:00\n        1    11:00:00+00:00\n        dtype: object\n\n        For DatetimeIndex:\n\n        >>> idx = pd.DatetimeIndex(\n        ...     ["1/1/2020 10:00:00+00:00", "2/1/2020 11:00:00+00:00"]\n        ... )\n        >>> idx.timetz\n        array([datetime.time(10, 0, tzinfo=datetime.timezone.utc),\n        datetime.time(11, 0, tzinfo=datetime.timezone.utc)], dtype=object)\n        """\n        return ints_to_pydatetime(self.asi8, self.tz, box="time", reso=self._creso)\n\n    @property\n    def date(self) -> npt.NDArray[np.object_]:\n        """\n        Returns numpy array of python :class:`datetime.date` objects.\n\n        Namely, the date part of Timestamps without time and\n        timezone information.\n\n        See Also\n        --------\n        DatetimeIndex.time : Returns numpy array of :class:`datetime.time` objects.\n            The time part of the Timestamps.\n        DatetimeIndex.year : The year of the datetime.\n        DatetimeIndex.month : The month as January=1, December=12.\n        DatetimeIndex.day : The day of the datetime.\n\n        Examples\n        --------\n        For Series:\n\n        >>> s = pd.Series(["1/1/2020 10:00:00+00:00", "2/1/2020 11:00:00+00:00"])\n        >>> s = pd.to_datetime(s)\n        >>> s\n        0   2020-01-01 10:00:00+00:00\n        1   2020-02-01 11:00:00+00:00\n        dtype: datetime64[us, UTC]\n        >>> s.dt.date\n        0    2020-01-01\n        1    2020-02-01\n        dtype: object\n\n        For DatetimeIndex:\n\n        >>> idx = pd.DatetimeIndex(\n        ...     ["1/1/2020 10:00:00+00:00", "2/1/2020 11:00:00+00:00"]\n        ... )\n        >>> idx.date\n        array([datetime.date(2020, 1, 1), datetime.date(2020, 2, 1)], dtype=object)\n        """\n        # If the Timestamps have a timezone that is not UTC,\n        # convert them into their i8 representation while\n        # keeping their timezone and not using UTC\n        timestamps = self._local_timestamps()\n\n        return ints_to_pydatetime(timestamps, box="date", reso=self._creso)\n\n    def isocalendar(self) -> DataFrame:\n        """\n        Calculate year, week, and day according to the ISO 8601 standard.\n\n        The ISO 8601 standard defines the first week of the year as the week\n        containing the first Thursday. This method returns a DataFrame with\n        columns for the ISO year, ISO week number, and ISO day of week.\n\n        Returns\n        -------\n        DataFrame\n            With columns year, week and day.\n\n        See Also\n        --------\n        Timestamp.isocalendar : Function return a 3-tuple containing ISO year,\n            week number, and weekday for the given Timestamp object.\n        datetime.date.isocalendar : Return a named tuple object with\n            three components: year, week and weekday.\n\n        Examples\n        --------\n        >>> idx = pd.date_range(start="2019-12-29", freq="D", periods=4)\n        >>> idx.isocalendar()\n                    year  week  day\n        2019-12-29  2019    52    7\n        2019-12-30  2020     1    1\n        2019-12-31  2020     1    2\n        2020-01-01  2020     1    3\n        >>> idx.isocalendar().week\n        2019-12-29    52\n        2019-12-30     1\n        2019-12-31     1\n        2020-01-01     1\n        Freq: D, Name: week, dtype: UInt32\n        """\n        from pandas import DataFrame\n\n        values = self._local_timestamps()\n        sarray = fields.build_isocalendar_sarray(values, reso=self._creso)\n        iso_calendar_df = DataFrame(\n            sarray, columns=["year", "week", "day"], dtype="UInt32"\n        )\n        if self._hasna:\n            iso_calendar_df.iloc[self._isnan] = None\n        return iso_calendar_df\n\n    year = _field_accessor(\n        "year",\n        "Y",\n        """\n        The year of the datetime.\n\n        This attribute returns the year component of each datetime value\n        in the Series/Index. The returned values are integers representing\n        the calendar year.\n\n        See Also\n        --------\n        DatetimeIndex.month: The month as January=1, December=12.\n        DatetimeIndex.day: The day of the datetime.\n\n        Examples\n        --------\n        >>> datetime_series = pd.Series(\n        ...     pd.date_range("2000-01-01", periods=3, freq="YE")\n        ... )\n        >>> datetime_series\n        0   2000-12-31\n        1   2001-12-31\n        2   2002-12-31\n        dtype: datetime64[us]\n        >>> datetime_series.dt.year\n        0    2000\n        1    2001\n        2    2002\n        dtype: int32\n        """,\n    )\n    month = _field_accessor(\n        "month",\n        "M",\n        """\n        The month as January=1, December=12.\n\n        This attribute returns the month component of each datetime value\n        in the Series/Index. Months are numbered from 1 (January) through\n        12 (December).\n\n        See Also\n        --------\n        DatetimeIndex.year: The year of the datetime.\n        DatetimeIndex.day: The day of the datetime.\n\n        Examples\n        --------\n        >>> datetime_series = pd.Series(\n        ...     pd.date_range("2000-01-01", periods=3, freq="ME")\n        ... )\n        >>> datetime_series\n        0   2000-01-31\n        1   2000-02-29\n        2   2000-03-31\n        dtype: datetime64[us]\n        >>> datetime_series.dt.month\n        0    1\n        1    2\n        2    3\n        dtype: int32\n        """,\n    )\n    day = _field_accessor(\n        "day",\n        "D",\n        """\n        The day of the datetime.\n\n        This attribute returns the day of the month component of each\n        datetime value in the Series/Index. Values range from 1 to 31,\n        depending on the month.\n\n        See Also\n        --------\n        DatetimeIndex.year: The year of the datetime.\n        DatetimeIndex.month: The month as January=1, December=12.\n        DatetimeIndex.hour: The hours of the datetime.\n\n        Examples\n        --------\n        >>> datetime_series = pd.Series(\n        ...     pd.date_range("2000-01-01", periods=3, freq="D")\n        ... )\n        >>> datetime_series\n        0   2000-01-01\n        1   2000-01-02\n        2   2000-01-03\n        dtype: datetime64[us]\n        >>> datetime_series.dt.day\n        0    1\n        1    2\n        2    3\n        dtype: int32\n        """,\n    )\n    hour = _field_accessor(\n        "hour",\n        "h",\n        """\n        The hours of the datetime.\n\n        This attribute returns the hour component of each datetime value\n        in the Series/Index. Values range from 0 to 23, representing the\n        hour of the day in 24-hour format.\n\n        See Also\n        --------\n        DatetimeIndex.day: The day of the datetime.\n        DatetimeIndex.minute: The minutes of the datetime.\n        DatetimeIndex.second: The seconds of the datetime.\n\n        Examples\n        --------\n        >>> datetime_series = pd.Series(\n        ...     pd.date_range("2000-01-01", periods=3, freq="h")\n        ... )\n        >>> datetime_series\n        0   2000-01-01 00:00:00\n        1   2000-01-01 01:00:00\n        2   2000-01-01 02:00:00\n        dtype: datetime64[us]\n        >>> datetime_series.dt.hour\n        0    0\n        1    1\n        2    2\n        dtype: int32\n        """,\n    )\n    minute = _field_accessor(\n        "minute",\n        "m",\n        """\n        The minutes of the datetime.\n\n        This attribute returns the minute component of each datetime value\n        in the Series/Index. Values range from 0 to 59.\n\n        See Also\n        --------\n        DatetimeIndex.hour: The hours of the datetime.\n        DatetimeIndex.second: The seconds of the datetime.\n\n        Examples\n        --------\n        >>> datetime_series = pd.Series(\n        ...     pd.date_range("2000-01-01", periods=3, freq="min")\n        ... )\n        >>> datetime_series\n        0   2000-01-01 00:00:00\n        1   2000-01-01 00:01:00\n        2   2000-01-01 00:02:00\n        dtype: datetime64[us]\n        >>> datetime_series.dt.minute\n        0    0\n        1    1\n        2    2\n        dtype: int32\n        """,\n    )\n    second = _field_accessor(\n        "second",\n        "s",\n        """\n        The seconds of the datetime.\n\n        This attribute returns the second component of each datetime value\n        in the Series/Index. Values range from 0 to 59.\n\n        See Also\n        --------\n        DatetimeIndex.minute: The minutes of the datetime.\n        DatetimeIndex.microsecond: The microseconds of the datetime.\n        DatetimeIndex.nanosecond: The nanoseconds of the datetime.\n\n        Examples\n        --------\n        >>> datetime_series = pd.Series(\n        ...     pd.date_range("2000-01-01", periods=3, freq="s")\n        ... )\n        >>> datetime_series\n        0   2000-01-01 00:00:00\n        1   2000-01-01 00:00:01\n        2   2000-01-01 00:00:02\n        dtype: datetime64[us]\n        >>> datetime_series.dt.second\n        0    0\n        1    1\n        2    2\n        dtype: int32\n        """,\n    )\n    microsecond = _field_accessor(\n        "microsecond",\n        "us",\n        """\n        The microseconds of the datetime.\n\n        This attribute returns the microsecond component of each datetime\n        value in the Series/Index. Values range from 0 to 999999\n        (one microsecond is one millionth of a second).\n\n        See Also\n        --------\n        DatetimeIndex.second: The seconds of the datetime.\n        DatetimeIndex.nanosecond: The nanoseconds of the datetime.\n\n        Examples\n        --------\n        >>> datetime_series = pd.Series(\n        ...     pd.date_range("2000-01-01", periods=3, freq="us")\n        ... )\n        >>> datetime_series\n        0   2000-01-01 00:00:00.000000\n        1   2000-01-01 00:00:00.000001\n        2   2000-01-01 00:00:00.000002\n        dtype: datetime64[us]\n        >>> datetime_series.dt.microsecond\n        0       0\n        1       1\n        2       2\n        dtype: int32\n        """,\n    )\n    nanosecond = _field_accessor(\n        "nanosecond",\n        "ns",\n        """\n        The nanoseconds of the datetime.\n\n        This attribute returns the nanosecond component of each datetime\n        value in the Series/Index. Values range from 0 to 999\n        (one nanosecond is one billionth of a second).\n\n        See Also\n        --------\n        DatetimeIndex.second: The seconds of the datetime.\n        DatetimeIndex.microsecond: The microseconds of the datetime.\n\n        Examples\n        --------\n        >>> datetime_series = pd.Series(\n        ...     pd.date_range("2000-01-01", periods=3, freq="ns")\n        ... )\n        >>> datetime_series\n        0   2000-01-01 00:00:00.000000000\n        1   2000-01-01 00:00:00.000000001\n        2   2000-01-01 00:00:00.000000002\n        dtype: datetime64[ns]\n        >>> datetime_series.dt.nanosecond\n        0       0\n        1       1\n        2       2\n        dtype: int32\n        """,\n    )\n    _dayofweek_doc = """\n    The day of the week with Monday=0, Sunday=6.\n\n    Return the day of the week. It is assumed the week starts on\n    Monday, which is denoted by 0 and ends on Sunday which is denoted\n    by 6. This method is available on both Series with datetime\n    values (using the `dt` accessor) or DatetimeIndex.\n\n    Returns\n    -------\n    Series or Index\n        Containing integers indicating the day number.\n\n    See Also\n    --------\n    Series.dt.dayofweek : Alias.\n    Series.dt.weekday : Alias.\n    Series.dt.day_name : Returns the name of the day of the week.\n\n    Examples\n    --------\n    >>> s = pd.date_range(\'2016-12-31\', \'2017-01-08\', freq=\'D\').to_series()\n    >>> s.dt.dayofweek\n    2016-12-31    5\n    2017-01-01    6\n    2017-01-02    0\n    2017-01-03    1\n    2017-01-04    2\n    2017-01-05    3\n    2017-01-06    4\n    2017-01-07    5\n    2017-01-08    6\n    Freq: D, dtype: int32\n    """\n    day_of_week = _field_accessor("day_of_week", "dow", _dayofweek_doc)\n    dayofweek = day_of_week\n    weekday = day_of_week\n\n    day_of_year = _field_accessor(\n        "dayofyear",\n        "doy",\n        """\n        The ordinal day of the year.\n\n        This attribute returns the day of the year for each datetime value\n        in the Series/Index. Values range from 1 to 365 (or 366 for leap years).\n\n        See Also\n        --------\n        DatetimeIndex.dayofweek : The day of the week with Monday=0, Sunday=6.\n        DatetimeIndex.day : The day of the datetime.\n\n        Examples\n        --------\n        For Series:\n\n        >>> s = pd.Series(["1/1/2020 10:00:00+00:00", "2/1/2020 11:00:00+00:00"])\n        >>> s = pd.to_datetime(s)\n        >>> s\n        0   2020-01-01 10:00:00+00:00\n        1   2020-02-01 11:00:00+00:00\n        dtype: datetime64[us, UTC]\n        >>> s.dt.dayofyear\n        0    1\n        1   32\n        dtype: int32\n\n        For DatetimeIndex:\n\n        >>> idx = pd.DatetimeIndex(["1/1/2020 10:00:00+00:00",\n        ...                         "2/1/2020 11:00:00+00:00"])\n        >>> idx.dayofyear\n        Index([1, 32], dtype=\'int32\')\n        """,\n    )\n    dayofyear = day_of_year\n    quarter = _field_accessor(\n        "quarter",\n        "q",\n        """\n        The quarter of the date.\n\n        This attribute returns the quarter of the year for each datetime value\n        in the Series/Index. Quarter 1 includes January through March, quarter 2\n        includes April through June, quarter 3 includes July through September,\n        and quarter 4 includes October through December.\n\n        See Also\n        --------\n        DatetimeIndex.snap : Snap time stamps to nearest occurring frequency.\n        DatetimeIndex.time : Returns numpy array of datetime.time objects.\n            The time part of the Timestamps.\n\n        Examples\n        --------\n        For Series:\n\n        >>> s = pd.Series(["1/1/2020 10:00:00+00:00", "4/1/2020 11:00:00+00:00"])\n        >>> s = pd.to_datetime(s)\n        >>> s\n        0   2020-01-01 10:00:00+00:00\n        1   2020-04-01 11:00:00+00:00\n        dtype: datetime64[us, UTC]\n        >>> s.dt.quarter\n        0    1\n        1    2\n        dtype: int32\n\n        For DatetimeIndex:\n\n        >>> idx = pd.DatetimeIndex(["1/1/2020 10:00:00+00:00",\n        ...                         "2/1/2020 11:00:00+00:00"])\n        >>> idx.quarter\n        Index([1, 1], dtype=\'int32\')\n        """,\n    )\n    days_in_month = _field_accessor(\n        "days_in_month",\n        "dim",\n        """\n        The number of days in the month.\n\n        This attribute returns the total number of days in the month for each\n        datetime value in the Series/Index. The value depends on the month and\n        whether the year is a leap year (e.g., February has 29 days in a leap year).\n\n        See Also\n        --------\n        Series.dt.day : Return the day of the month.\n        Series.dt.is_month_end : Return a boolean indicating if the\n            date is the last day of the month.\n        Series.dt.is_month_start : Return a boolean indicating if the\n            date is the first day of the month.\n        Series.dt.month : Return the month as January=1 through December=12.\n\n        Examples\n        --------\n        >>> s = pd.Series(["1/1/2020 10:00:00+00:00", "2/1/2020 11:00:00+00:00"])\n        >>> s = pd.to_datetime(s)\n        >>> s\n        0   2020-01-01 10:00:00+00:00\n        1   2020-02-01 11:00:00+00:00\n        dtype: datetime64[us, UTC]\n        >>> s.dt.daysinmonth\n        0    31\n        1    29\n        dtype: int32\n        """,\n    )\n    daysinmonth = days_in_month\n    _is_month_doc = """\n        Indicates whether the date is the {first_or_last} day of the month.\n\n        This boolean attribute evaluates to True if the date falls on the\n        {first_or_last} day of a calendar month, and False otherwise.\n\n        Returns\n        -------\n        Series or array\n            For Series, returns a Series with boolean values.\n            For DatetimeIndex, returns a boolean array.\n\n        See Also\n        --------\n        is_month_start : Return a boolean indicating whether the date\n            is the first day of the month.\n        is_month_end : Return a boolean indicating whether the date\n            is the last day of the month.\n\n        Examples\n        --------\n        This method is available on Series with datetime values under\n        the ``.dt`` accessor, and directly on DatetimeIndex.\n\n        >>> s = pd.Series(pd.date_range("2018-02-27", periods=3))\n        >>> s\n        0   2018-02-27\n        1   2018-02-28\n        2   2018-03-01\n        dtype: datetime64[us]\n        >>> s.dt.is_month_start\n        0    False\n        1    False\n        2    True\n        dtype: bool\n        >>> s.dt.is_month_end\n        0    False\n        1    True\n        2    False\n        dtype: bool\n\n        >>> idx = pd.date_range("2018-02-27", periods=3)\n        >>> idx.is_month_start\n        array([False, False, True])\n        >>> idx.is_month_end\n        array([False, True, False])\n    """\n    is_month_start = _field_accessor(\n        "is_month_start", "is_month_start", _is_month_doc.format(first_or_last="first")\n    )\n\n    is_month_end = _field_accessor(\n        "is_month_end", "is_month_end", _is_month_doc.format(first_or_last="last")\n    )\n\n    is_quarter_start = _field_accessor(\n        "is_quarter_start",\n        "is_quarter_start",\n        """\n        Indicator for whether the date is the first day of a quarter.\n\n        This boolean attribute evaluates to True if the date falls on the\n        first day of a calendar quarter (January 1, April 1, July 1, or\n        October 1), and False otherwise.\n\n        Returns\n        -------\n        is_quarter_start : Series or DatetimeIndex\n            The same type as the original data with boolean values. Series will\n            have the same name and index. DatetimeIndex will have the same\n            name.\n\n        See Also\n        --------\n        quarter : Return the quarter of the date.\n        is_quarter_end : Similar property for indicating the quarter end.\n\n        Examples\n        --------\n        This method is available on Series with datetime values under\n        the ``.dt`` accessor, and directly on DatetimeIndex.\n\n        >>> df = pd.DataFrame({\'dates\': pd.date_range("2017-03-30",\n        ...                   periods=4)})\n        >>> df.assign(quarter=df.dates.dt.quarter,\n        ...           is_quarter_start=df.dates.dt.is_quarter_start)\n               dates  quarter  is_quarter_start\n        0 2017-03-30        1             False\n        1 2017-03-31        1             False\n        2 2017-04-01        2              True\n        3 2017-04-02        2             False\n\n        >>> idx = pd.date_range(\'2017-03-30\', periods=4)\n        >>> idx\n        DatetimeIndex([\'2017-03-30\', \'2017-03-31\', \'2017-04-01\', \'2017-04-02\'],\n                      dtype=\'datetime64[us]\', freq=\'D\')\n\n        >>> idx.is_quarter_start\n        array([False, False,  True, False])\n        """,\n    )\n    is_quarter_end = _field_accessor(\n        "is_quarter_end",\n        "is_quarter_end",\n        """\n        Indicator for whether the date is the last day of a quarter.\n\n        This boolean attribute evaluates to True if the date falls on the\n        last day of a calendar quarter (March 31, June 30, September 30, or\n        December 31), and False otherwise.\n\n        Returns\n        -------\n        is_quarter_end : Series or DatetimeIndex\n            The same type as the original data with boolean values. Series will\n            have the same name and index. DatetimeIndex will have the same\n            name.\n\n        See Also\n        --------\n        quarter : Return the quarter of the date.\n        is_quarter_start : Similar property indicating the quarter start.\n\n        Examples\n        --------\n        This method is available on Series with datetime values under\n        the ``.dt`` accessor, and directly on DatetimeIndex.\n\n        >>> df = pd.DataFrame({\'dates\': pd.date_range("2017-03-30",\n        ...                    periods=4)})\n        >>> df.assign(quarter=df.dates.dt.quarter,\n        ...           is_quarter_end=df.dates.dt.is_quarter_end)\n               dates  quarter    is_quarter_end\n        0 2017-03-30        1             False\n        1 2017-03-31        1              True\n        2 2017-04-01        2             False\n        3 2017-04-02        2             False\n\n        >>> idx = pd.date_range(\'2017-03-30\', periods=4)\n        >>> idx\n        DatetimeIndex([\'2017-03-30\', \'2017-03-31\', \'2017-04-01\', \'2017-04-02\'],\n                      dtype=\'datetime64[us]\', freq=\'D\')\n\n        >>> idx.is_quarter_end\n        array([False,  True, False, False])\n        """,\n    )\n    is_year_start = _field_accessor(\n        "is_year_start",\n        "is_year_start",\n        """\n        Indicate whether the date is the first day of a year.\n\n        This boolean attribute evaluates to True if the date is January 1st,\n        and False otherwise.\n\n        Returns\n        -------\n        Series or DatetimeIndex\n            The same type as the original data with boolean values. Series will\n            have the same name and index. DatetimeIndex will have the same\n            name.\n\n        See Also\n        --------\n        is_year_end : Similar property indicating the last day of the year.\n\n        Examples\n        --------\n        This method is available on Series with datetime values under\n        the ``.dt`` accessor, and directly on DatetimeIndex.\n\n        >>> dates = pd.Series(pd.date_range("2017-12-30", periods=3))\n        >>> dates\n        0   2017-12-30\n        1   2017-12-31\n        2   2018-01-01\n        dtype: datetime64[us]\n\n        >>> dates.dt.is_year_start\n        0    False\n        1    False\n        2    True\n        dtype: bool\n\n        >>> idx = pd.date_range("2017-12-30", periods=3)\n        >>> idx\n        DatetimeIndex([\'2017-12-30\', \'2017-12-31\', \'2018-01-01\'],\n                      dtype=\'datetime64[us]\', freq=\'D\')\n\n        >>> idx.is_year_start\n        array([False, False,  True])\n\n        This method, when applied to Series with datetime values under\n        the ``.dt`` accessor, will lose information about Business offsets.\n\n        >>> dates = pd.Series(pd.date_range("2020-10-30", periods=4, freq="BYS"))\n        >>> dates\n        0   2021-01-01\n        1   2022-01-03\n        2   2023-01-02\n        3   2024-01-01\n        dtype: datetime64[us]\n\n        >>> dates.dt.is_year_start\n        0    True\n        1    False\n        2    False\n        3    True\n        dtype: bool\n\n        >>> idx = pd.date_range("2020-10-30", periods=4, freq="BYS")\n        >>> idx\n        DatetimeIndex([\'2021-01-01\', \'2022-01-03\', \'2023-01-02\', \'2024-01-01\'],\n                      dtype=\'datetime64[us]\', freq=\'BYS-JAN\')\n\n        >>> idx.is_year_start\n        array([ True,  True,  True,  True])\n        """,\n    )\n    is_year_end = _field_accessor(\n        "is_year_end",\n        "is_year_end",\n        """\n        Indicate whether the date is the last day of the year.\n\n        This boolean attribute evaluates to True if the date is December 31st,\n        and False otherwise.\n\n        Returns\n        -------\n        Series or DatetimeIndex\n            The same type as the original data with boolean values. Series will\n            have the same name and index. DatetimeIndex will have the same\n            name.\n\n        See Also\n        --------\n        is_year_start : Similar property indicating the start of the year.\n\n        Examples\n        --------\n        This method is available on Series with datetime values under\n        the ``.dt`` accessor, and directly on DatetimeIndex.\n\n        >>> dates = pd.Series(pd.date_range("2017-12-30", periods=3))\n        >>> dates\n        0   2017-12-30\n        1   2017-12-31\n        2   2018-01-01\n        dtype: datetime64[us]\n\n        >>> dates.dt.is_year_end\n        0    False\n        1     True\n        2    False\n        dtype: bool\n\n        >>> idx = pd.date_range("2017-12-30", periods=3)\n        >>> idx\n        DatetimeIndex([\'2017-12-30\', \'2017-12-31\', \'2018-01-01\'],\n                      dtype=\'datetime64[us]\', freq=\'D\')\n\n        >>> idx.is_year_end\n        array([False,  True, False])\n        """,\n    )\n    is_leap_year = _field_accessor(\n        "is_leap_year",\n        "is_leap_year",\n        """\n        Boolean indicator if the date belongs to a leap year.\n\n        A leap year is a year, which has 366 days (instead of 365) including\n        29th of February as an intercalary day.\n        Leap years are years which are multiples of four with the exception\n        of years divisible by 100 but not by 400.\n\n        Returns\n        -------\n        Series or ndarray\n             Booleans indicating if dates belong to a leap year.\n\n        See Also\n        --------\n        DatetimeIndex.is_year_end : Indicate whether the date is the\n            last day of the year.\n        DatetimeIndex.is_year_start : Indicate whether the date is the first\n            day of a year.\n\n        Examples\n        --------\n        This method is available on Series with datetime values under\n        the ``.dt`` accessor, and directly on DatetimeIndex.\n\n        >>> idx = pd.date_range("2012-01-01", "2015-01-01", freq="YE")\n        >>> idx\n        DatetimeIndex([\'2012-12-31\', \'2013-12-31\', \'2014-12-31\'],\n                      dtype=\'datetime64[us]\', freq=\'YE-DEC\')\n        >>> idx.is_leap_year\n        array([ True, False, False])\n\n        >>> dates_series = pd.Series(idx)\n        >>> dates_series\n        0   2012-12-31\n        1   2013-12-31\n        2   2014-12-31\n        dtype: datetime64[us]\n        >>> dates_series.dt.is_leap_year\n        0     True\n        1    False\n        2    False\n        dtype: bool\n        """,\n    )\n\n    def to_julian_date(self) -> npt.NDArray[np.float64]:\n        """\n        Convert Timestamp to a Julian Date.\n\n        This method returns the number of days as a float since noon January 1, 4713 BC.\n\n        https://en.wikipedia.org/wiki/Julian_day\n\n        Returns\n        -------\n        ndarray or Index\n            Float values that represent each date in Julian Calendar.\n\n        See Also\n        --------\n        Timestamp.to_julian_date : Equivalent method on ``Timestamp`` objects.\n\n        Examples\n        --------\n        >>> idx = pd.DatetimeIndex(["2028-08-12 00:54", "2028-08-12 02:06"])\n        >>> idx.to_julian_date()\n        Index([2461995.5375, 2461995.5875], dtype=\'float64\')\n        """\n\n        # http://mysite.verizon.net/aesir_research/date/jdalg2.htm\n        year = np.asarray(self.year)\n        month = np.asarray(self.month)\n        day = np.asarray(self.day)\n        testarr = month < 3\n        year[testarr] -= 1\n        month[testarr] += 12\n        return (\n            day\n            + np.trunc((153 * month - 457) / 5)\n            + 365 * year\n            + np.floor(year / 4)\n            - np.floor(year / 100)\n            + np.floor(year / 400)\n            + 1_721_118.5\n            + (\n                self.hour\n                + self.minute / 60\n                + self.second / 3600\n                + self.microsecond / 3600 / 10**6\n                + self.nanosecond / 3600 / 10**9\n            )\n            / 24\n        )\n\n    # -----------------------------------------------------------------\n    # Reductions\n\n    def _reduce(\n        self, name: str, *, skipna: bool = True, keepdims: bool = False, **kwargs\n    ):\n        result = super()._reduce(name, skipna=skipna, keepdims=keepdims, **kwargs)\n        if keepdims and isinstance(result, np.ndarray):\n            if name == "std":\n                from pandas.core.arrays import TimedeltaArray\n\n                return TimedeltaArray._from_sequence(result)\n            else:\n                return self._from_sequence(result, dtype=self.dtype)\n        return result\n\n    def std(\n        self,\n        axis=None,\n        dtype=None,\n        out=None,\n        ddof: int = 1,\n        keepdims: bool = False,\n        skipna: bool = True,\n    ) -> Timedelta:\n        """\n        Return sample standard deviation over requested axis.\n\n        Normalized by `N-1` by default. This can be changed using ``ddof``.\n\n        Parameters\n        ----------\n        axis : int, optional\n            Axis for the function to be applied on. For :class:`pandas.Series`\n            this parameter is unused and defaults to ``None``.\n        dtype : dtype, optional, default None\n            Type to use in computing the standard deviation. For arrays of\n            integer type the default is float64, for arrays of float types\n            it is the same as the array type.\n        out : ndarray, optional, default None\n            Alternative output array in which to place the result. It must have\n            the same shape as the expected output but the type (of the\n            calculated values) will be cast if necessary.\n        ddof : int, default 1\n            Degrees of Freedom. The divisor used in calculations is `N - ddof`,\n            where `N` represents the number of elements.\n        keepdims : bool, optional\n            If this is set to True, the axes which are reduced are left in the\n            result as dimensions with size one. With this option, the result\n            will broadcast correctly against the input array. If the default\n            value is passed, then keepdims will not be passed through to the\n            std method of sub-classes of ndarray, however any non-default value\n            will be. If the sub-class method does not implement keepdims any\n            exceptions will be raised.\n        skipna : bool, default True\n            Exclude NA/null values. If an entire row/column is ``NA``, the result\n            will be ``NA``.\n\n        Returns\n        -------\n        Timedelta\n            Standard deviation over requested axis.\n\n        See Also\n        --------\n        numpy.ndarray.std : Returns the standard deviation of the array elements\n            along given axis.\n        Series.std : Return sample standard deviation over requested axis.\n\n        Examples\n        --------\n        For :class:`pandas.DatetimeIndex`:\n\n        >>> idx = pd.date_range("2001-01-01 00:00", periods=3)\n        >>> idx\n        DatetimeIndex([\'2001-01-01\', \'2001-01-02\', \'2001-01-03\'],\n                      dtype=\'datetime64[us]\', freq=\'D\')\n        >>> idx.std()\n        Timedelta(\'1 days 00:00:00\')\n        """\n        # Because std is translation-invariant, we can get self.std\n        #  by calculating (self - Timestamp(0)).std, and we can do it\n        #  without creating a copy by using a view on self._ndarray\n        from pandas.core.arrays import TimedeltaArray\n\n        # Find the td64 dtype with the same resolution as our dt64 dtype\n        dtype_str = self._ndarray.dtype.name.replace("datetime64", "timedelta64")\n        dtype = np.dtype(dtype_str)\n\n        tda = TimedeltaArray._simple_new(self._ndarray.view(dtype), dtype=dtype)\n\n        return tda.std(axis=axis, out=out, ddof=ddof, keepdims=keepdims, skipna=skipna)\n\n\n# -------------------------------------------------------------------\n# Constructor Helpers\n\n\ndef _sequence_to_dt64(\n    data: ArrayLike,\n    *,\n    copy: bool = False,\n    tz: tzinfo | None = None,\n    dayfirst: bool = False,\n    yearfirst: bool = False,\n    ambiguous: TimeAmbiguous = "raise",\n    out_unit: str | None = None,\n) -> tuple[np.ndarray, tzinfo | None]:\n    """\n    Parameters\n    ----------\n    data : np.ndarray or ExtensionArray\n        dtl.ensure_arraylike_for_datetimelike has already been called.\n    copy : bool, default False\n    tz : tzinfo or None, default None\n    dayfirst : bool, default False\n    yearfirst : bool, default False\n    ambiguous : str, bool, or arraylike, default \'raise\'\n        See pandas._libs.tslibs.tzconversion.tz_localize_to_utc.\n    out_unit : str or None, default None\n        Desired output resolution.\n\n    Returns\n    -------\n    result : numpy.ndarray\n        The sequence converted to a numpy array with dtype ``datetime64[unit]``.\n        Where `unit` is "ns" unless specified otherwise by `out_unit`.\n    tz : tzinfo or None\n        Either the user-provided tzinfo or one inferred from the data.\n\n    Raises\n    ------\n    TypeError : PeriodDType data is passed\n    """\n\n    # By this point we are assured to have either a numpy array or Index\n    data, copy = maybe_convert_dtype(data, copy, tz=tz)\n    data_dtype = getattr(data, "dtype", None)\n\n    out_dtype = DT64NS_DTYPE\n    if out_unit is not None:\n        out_dtype = np.dtype(f"M8[{out_unit}]")\n\n    if data_dtype == object or is_string_dtype(data_dtype):\n        # TODO: We do not have tests specific to string-dtypes,\n        #  also complex or categorical or other extension\n        data = cast("np.ndarray", data)\n        copy = False\n        if lib.infer_dtype(data, skipna=False) == "integer":\n            # Much more performant than going through array_to_datetime\n            data = data.astype(np.int64)\n        elif tz is not None and ambiguous == "raise":\n            obj_data = np.asarray(data, dtype=object)\n            result = tslib.array_to_datetime_with_tz(\n                obj_data,\n                tz=tz,\n                dayfirst=dayfirst,\n                yearfirst=yearfirst,\n                creso=abbrev_to_npy_unit(out_unit),\n            )\n            return result, tz\n        else:\n            converted, inferred_tz = objects_to_datetime64(\n                data,\n                dayfirst=dayfirst,\n                yearfirst=yearfirst,\n                allow_object=False,\n                out_unit=out_unit,\n            )\n            copy = False\n            if tz and inferred_tz:\n                #  two timezones: convert to intended from base UTC repr\n                # GH#42505 by convention, these are _already_ UTC\n                result = converted\n\n            elif inferred_tz:\n                tz = inferred_tz\n                result = converted\n\n            else:\n                result, _ = _construct_from_dt64_naive(\n                    converted, tz=tz, copy=copy, ambiguous=ambiguous\n                )\n            return result, tz\n\n        data_dtype = data.dtype\n\n    # `data` may have originally been a Categorical[datetime64[ns, tz]],\n    # so we need to handle these types.\n    if isinstance(data_dtype, DatetimeTZDtype):\n        # DatetimeArray -> ndarray\n        data = cast("DatetimeArray", data)\n        tz = _maybe_infer_tz(tz, data.tz)\n        result = data._ndarray\n\n    elif lib.is_np_dtype(data_dtype, "M"):\n        # tz-naive DatetimeArray or ndarray[datetime64]\n        if isinstance(data, DatetimeArray):\n            data = data._ndarray\n\n        data = cast("np.ndarray", data)\n        result, copy = _construct_from_dt64_naive(\n            data, tz=tz, copy=copy, ambiguous=ambiguous\n        )\n\n    else:\n        # must be integer dtype otherwise\n        # assume this data are epoch timestamps\n        if data.dtype != INT64_DTYPE:\n            data = data.astype(np.int64, copy=False)\n            copy = False\n        data = cast("np.ndarray", data)\n        result = data.view(out_dtype)\n\n    if copy:\n        result = result.copy()\n\n    assert isinstance(result, np.ndarray), type(result)\n    assert result.dtype.kind == "M"\n    assert result.dtype != "M8"\n    assert is_supported_dtype(result.dtype)\n    return result, tz\n\n\ndef _construct_from_dt64_naive(\n    data: np.ndarray, *, tz: tzinfo | None, copy: bool, ambiguous: TimeAmbiguous\n) -> tuple[np.ndarray, bool]:\n    """\n    Convert datetime64 data to a supported dtype, localizing if necessary.\n    """\n    # Caller is responsible for ensuring\n    #  lib.is_np_dtype(data.dtype)\n\n    new_dtype = data.dtype\n    if not is_supported_dtype(new_dtype):\n        # Cast to the nearest supported unit, generally "s"\n        new_dtype = get_supported_dtype(new_dtype)\n        data = astype_overflowsafe(data, dtype=new_dtype, copy=False)\n        copy = False\n\n    if data.dtype.byteorder == ">":\n        # TODO: better way to handle this?  non-copying alternative?\n        #  without this, test_constructor_datetime64_bigendian fails\n        data = data.astype(data.dtype.newbyteorder("<"))\n        new_dtype = data.dtype\n        copy = False\n\n    if tz is not None:\n        # Convert tz-naive to UTC\n        # TODO: if tz is UTC, are there situations where we *don\'t* want a\n        #  copy?  tz_localize_to_utc always makes one.\n        shape = data.shape\n        if data.ndim > 1:\n            data = data.ravel()\n\n        data_unit = get_unit_from_dtype(new_dtype)\n        data = tzconversion.tz_localize_to_utc(\n            data.view("i8"), tz, ambiguous=ambiguous, creso=data_unit\n        )\n        data = data.view(new_dtype)\n        data = data.reshape(shape)\n\n    assert data.dtype == new_dtype, data.dtype\n    result = data\n\n    return result, copy\n\n\ndef objects_to_datetime64(\n    data: np.ndarray,\n    dayfirst,\n    yearfirst,\n    utc: bool = False,\n    errors: DateTimeErrorChoices = "raise",\n    allow_object: bool = False,\n    out_unit: str | None = None,\n) -> tuple[np.ndarray, tzinfo | None]:\n    """\n    Convert data to array of timestamps.\n\n    Parameters\n    ----------\n    data : np.ndarray[object]\n    dayfirst : bool\n    yearfirst : bool\n    utc : bool, default False\n        Whether to convert/localize timestamps to UTC.\n    errors : {\'raise\', \'coerce\'}\n    allow_object : bool\n        Whether to return an object-dtype ndarray instead of raising if the\n        data contains more than one timezone.\n    out_unit : str or None, default None\n        None indicates we should do resolution inference.\n\n    Returns\n    -------\n    result : ndarray\n        np.datetime64[out_unit] if returned values represent wall times or UTC\n        timestamps.\n        object if mixed timezones\n    inferred_tz : tzinfo or None\n        If not None, then the datetime64 values in `result` denote UTC timestamps.\n\n    Raises\n    ------\n    ValueError : if data cannot be converted to datetimes\n    TypeError  : When a type cannot be converted to datetime\n    """\n    assert errors in ["raise", "coerce"]\n\n    # if str-dtype, convert\n    data = np.asarray(data, dtype=np.object_)\n\n    result, tz_parsed = tslib.array_to_datetime(\n        data,\n        errors=errors,\n        utc=utc,\n        dayfirst=dayfirst,\n        yearfirst=yearfirst,\n        creso=abbrev_to_npy_unit(out_unit),\n    )\n\n    if tz_parsed is not None:\n        # We can take a shortcut since the datetime64 numpy array\n        #  is in UTC\n        return result, tz_parsed\n    elif result.dtype.kind == "M":\n        return result, tz_parsed\n    elif result.dtype == object:\n        # GH#23675 when called via `pd.to_datetime`, returning an object-dtype\n        #  array is allowed.  When called via `pd.DatetimeIndex`, we can\n        #  only accept datetime64 dtype, so raise TypeError if object-dtype\n        #  is returned, as that indicates the values can be recognized as\n        #  datetimes but they have conflicting timezones/awareness\n        if allow_object:\n            return result, tz_parsed\n        raise TypeError("DatetimeIndex has mixed timezones")\n    else:  # pragma: no cover\n        # GH#23675 this TypeError should never be hit, whereas the TypeError\n        #  in the object-dtype branch above is reachable.\n        raise TypeError(result)\n\n\ndef maybe_convert_dtype(data, copy: bool, tz: tzinfo | None = None):\n    """\n    Convert data based on dtype conventions, issuing\n    errors where appropriate.\n\n    Parameters\n    ----------\n    data : np.ndarray or pd.Index\n    copy : bool\n    tz : tzinfo or None, default None\n\n    Returns\n    -------\n    data : np.ndarray or pd.Index\n    copy : bool\n\n    Raises\n    ------\n    TypeError : PeriodDType data is passed\n    """\n    if not hasattr(data, "dtype"):\n        # e.g. collections.deque\n        return data, copy\n\n    if is_float_dtype(data.dtype):\n        # pre-2.0 we treated these as wall-times, inconsistent with ints\n        # GH#23675, GH#45573 deprecated to treat symmetrically with integer dtypes.\n        # Note: data.astype(np.int64) fails ARM tests, see\n        # https://github.com/pandas-dev/pandas/issues/49468.\n        data = data.astype(DT64NS_DTYPE).view("i8")\n        copy = False\n\n    elif lib.is_np_dtype(data.dtype, "m") or is_bool_dtype(data.dtype):\n        # GH#29794 enforcing deprecation introduced in GH#23539\n        raise TypeError(f"dtype {data.dtype} cannot be converted to datetime64[ns]")\n    elif isinstance(data.dtype, PeriodDtype):\n        # Note: without explicitly raising here, PeriodIndex\n        #  test_setops.test_join_does_not_recur fails\n        raise TypeError(\n            "Passing PeriodDtype data is invalid. Use `data.to_timestamp()` instead"\n        )\n\n    elif isinstance(data.dtype, ExtensionDtype) and not isinstance(\n        data.dtype, DatetimeTZDtype\n    ):\n        # TODO: We have no tests for these\n        data = np.array(data, dtype=np.object_)\n        copy = False\n\n    return data, copy\n\n\n# -------------------------------------------------------------------\n# Validation and Inference\n\n\ndef _maybe_infer_tz(tz: tzinfo | None, inferred_tz: tzinfo | None) -> tzinfo | None:\n    """\n    If a timezone is inferred from data, check that it is compatible with\n    the user-provided timezone, if any.\n\n    Parameters\n    ----------\n    tz : tzinfo or None\n    inferred_tz : tzinfo or None\n\n    Returns\n    -------\n    tz : tzinfo or None\n\n    Raises\n    ------\n    TypeError : if both timezones are present but do not match\n    """\n    if tz is None:\n        tz = inferred_tz\n    elif inferred_tz is None:\n        pass\n    elif not timezones.tz_compare(tz, inferred_tz):\n        raise TypeError(\n            f"data is already tz-aware {inferred_tz}, unable to set specified tz: {tz}"\n        )\n    return tz\n\n\ndef _validate_dt64_dtype(dtype):\n    """\n    Check that a dtype, if passed, represents either a numpy datetime64[ns]\n    dtype or a pandas DatetimeTZDtype.\n\n    Parameters\n    ----------\n    dtype : object\n\n    Returns\n    -------\n    dtype : None, numpy.dtype, or DatetimeTZDtype\n\n    Raises\n    ------\n    ValueError : invalid dtype\n\n    Notes\n    -----\n    Unlike _validate_tz_from_dtype, this does _not_ allow non-existent\n    tz errors to go through\n    """\n    if dtype is not None:\n        dtype = pandas_dtype(dtype)\n        if dtype == np.dtype("M8"):\n            # no precision, disallowed GH#24806\n            msg = (\n                "Passing in \'datetime64\' dtype with no precision is not allowed. "\n                "Please pass in \'datetime64[ns]\' instead."\n            )\n            raise ValueError(msg)\n\n        if (\n            isinstance(dtype, np.dtype)\n            and (dtype.kind != "M" or not is_supported_dtype(dtype))\n        ) or not isinstance(dtype, (np.dtype, DatetimeTZDtype)):\n            raise ValueError(\n                f"Unexpected value for \'dtype\': \'{dtype}\'. "\n                "Must be \'datetime64[s]\', \'datetime64[ms]\', \'datetime64[us]\', "\n                "\'datetime64[ns]\' or DatetimeTZDtype\'."\n            )\n\n        if getattr(dtype, "tz", None):\n            # https://github.com/pandas-dev/pandas/issues/18595\n            # Ensure that we have a standard timezone for pytz objects.\n            # Without this, things like adding an array of timedeltas and\n            # a  tz-aware Timestamp (with a tz specific to its datetime) will\n            # be incorrect(ish?) for the array as a whole\n            dtype = cast("DatetimeTZDtype", dtype)\n            dtype = DatetimeTZDtype(\n                unit=dtype.unit, tz=timezones.tz_standardize(dtype.tz)\n            )\n\n    return dtype\n\n\ndef _validate_tz_from_dtype(\n    dtype, tz: tzinfo | None, explicit_tz_none: bool = False\n) -> tzinfo | None:\n    """\n    If the given dtype is a DatetimeTZDtype, extract the implied\n    tzinfo object from it and check that it does not conflict with the given\n    tz.\n\n    Parameters\n    ----------\n    dtype : dtype, str\n    tz : None, tzinfo\n    explicit_tz_none : bool, default False\n        Whether tz=None was passed explicitly, as opposed to lib.no_default.\n\n    Returns\n    -------\n    tz : consensus tzinfo\n\n    Raises\n    ------\n    ValueError : on tzinfo mismatch\n    """\n    if dtype is not None:\n        if isinstance(dtype, str):\n            try:\n                dtype = DatetimeTZDtype.construct_from_string(dtype)\n            except TypeError:\n                # Things like `datetime64[ns]`, which is OK for the\n                # constructors, but also nonsense, which should be validated\n                # but not by us. We *do* allow non-existent tz errors to\n                # go through\n                pass\n        dtz = getattr(dtype, "tz", None)\n        if dtz is not None:\n            if tz is not None and not timezones.tz_compare(tz, dtz):\n                raise ValueError("cannot supply both a tz and a dtype with a tz")\n            if explicit_tz_none:\n                raise ValueError("Cannot pass both a timezone-aware dtype and tz=None")\n            tz = dtz\n\n        if tz is not None and lib.is_np_dtype(dtype, "M"):\n            # We also need to check for the case where the user passed a\n            #  tz-naive dtype (i.e. datetime64[ns])\n            if tz is not None and not timezones.tz_compare(tz, dtz):\n                raise ValueError(\n                    "cannot supply both a tz and a "\n                    "timezone-naive dtype (i.e. datetime64[ns])"\n                )\n\n    return tz\n\n\ndef _infer_tz_from_endpoints(\n    start: Timestamp, end: Timestamp, tz: tzinfo | None\n) -> tzinfo | None:\n    """\n    If a timezone is not explicitly given via `tz`, see if one can\n    be inferred from the `start` and `end` endpoints.  If more than one\n    of these inputs provides a timezone, require that they all agree.\n\n    Parameters\n    ----------\n    start : Timestamp\n    end : Timestamp\n    tz : tzinfo or None\n\n    Returns\n    -------\n    tz : tzinfo or None\n\n    Raises\n    ------\n    TypeError : if start and end timezones do not agree\n    """\n    try:\n        inferred_tz = timezones.infer_tzinfo(start, end)\n    except AssertionError as err:\n        # infer_tzinfo raises AssertionError if passed mismatched timezones\n        raise TypeError(\n            "Start and end cannot both be tz-aware with different timezones"\n        ) from err\n\n    inferred_tz = timezones.maybe_get_tz(inferred_tz)\n    tz = timezones.maybe_get_tz(tz)\n\n    if tz is not None and inferred_tz is not None:\n        if not timezones.tz_compare(inferred_tz, tz):\n            raise AssertionError("Inferred time zone not equal to passed time zone")\n\n    elif inferred_tz is not None:\n        tz = inferred_tz\n\n    return tz\n\n\ndef _maybe_normalize_endpoints(\n    start: _TimestampNoneT1, end: _TimestampNoneT2, normalize: bool\n) -> tuple[_TimestampNoneT1, _TimestampNoneT2]:\n    if normalize:\n        if start is not None:\n            start = start.normalize()\n\n        if end is not None:\n            end = end.normalize()\n\n    return start, end\n\n\ndef _maybe_localize_point(\n    ts: Timestamp | None, freq, tz, ambiguous, nonexistent\n) -> Timestamp | None:\n    """\n    Localize a start or end Timestamp to the timezone of the corresponding\n    start or end Timestamp\n\n    Parameters\n    ----------\n    ts : start or end Timestamp to potentially localize\n    freq : Tick, DateOffset, or None\n    tz : str, timezone object or None\n    ambiguous: str, localization behavior for ambiguous times\n    nonexistent: str, localization behavior for nonexistent times\n\n    Returns\n    -------\n    ts : Timestamp\n    """\n    # Make sure start and end are timezone localized if:\n    # 1) freq = a Timedelta-like frequency (Tick)\n    # 2) freq = None i.e. generating a linspaced range\n    if ts is not None and ts.tzinfo is None:\n        # Note: We can\'t ambiguous=\'infer\' a singular ambiguous time; however,\n        # we have historically defaulted ambiguous=False\n        ambiguous = ambiguous if ambiguous != "infer" else False\n        localize_args = {"ambiguous": ambiguous, "nonexistent": nonexistent, "tz": None}\n        if isinstance(freq, Tick) or freq is None:\n            localize_args["tz"] = tz\n        ts = ts.tz_localize(**localize_args)\n    return ts\n\n\ndef _generate_range(\n    start: Timestamp | None,\n    end: Timestamp | None,\n    periods: int | None,\n    offset: BaseOffset,\n    *,\n    unit: TimeUnit,\n) -> Generator[Timestamp]:\n    """\n    Generates a sequence of dates corresponding to the specified time\n    offset. Similar to dateutil.rrule except uses pandas DateOffset\n    objects to represent time increments.\n\n    Parameters\n    ----------\n    start : Timestamp or None\n    end : Timestamp or None\n    periods : int or None\n    offset : DateOffset\n    unit : str\n\n    Notes\n    -----\n    * This method is faster for generating weekdays than dateutil.rrule\n    * At least two of (start, end, periods) must be specified.\n    * If both start and end are specified, the returned dates will\n    satisfy start <= date <= end.\n\n    Returns\n    -------\n    dates : generator object\n    """\n    offset = to_offset(offset)\n\n    # Argument 1 to "Timestamp" has incompatible type "Optional[Timestamp]";\n    # expected "Union[integer[Any], float, str, date, datetime64]"\n    start = Timestamp(start)  # type: ignore[arg-type]\n    if start is not NaT:\n        start = start.as_unit(unit)\n    else:\n        start = None\n\n    # Argument 1 to "Timestamp" has incompatible type "Optional[Timestamp]";\n    # expected "Union[integer[Any], float, str, date, datetime64]"\n    end = Timestamp(end)  # type: ignore[arg-type]\n    if end is not NaT:\n        end = end.as_unit(unit)\n    else:\n        end = None\n\n    if start and not offset.is_on_offset(start):\n        # Incompatible types in assignment (expression has type "datetime",\n        # variable has type "Optional[Timestamp]")\n\n        # GH #56147 account for negative direction and range bounds\n        if offset.n >= 0:\n            start = offset.rollforward(start)  # type: ignore[assignment]\n        else:\n            start = offset.rollback(start)  # type: ignore[assignment]\n\n    # Unsupported operand types for < ("Timestamp" and "None")\n    if periods is None and end < start and offset.n >= 0:  # type: ignore[operator]\n        end = None\n        periods = 0\n\n    if end is None:\n        # error: No overload variant of "__radd__" of "BaseOffset" matches\n        # argument type "None"\n        end = start + (periods - 1) * offset  # type: ignore[operator]\n\n    if start is None:\n        # error: No overload variant of "__radd__" of "BaseOffset" matches\n        # argument type "None"\n        start = end - (periods - 1) * offset  # type: ignore[operator]\n\n    start = cast("Timestamp", start)\n    end = cast("Timestamp", end)\n\n    cur = start\n    if offset.n >= 0:\n        while cur <= end:\n            yield cur\n\n            if cur == end:\n                # GH#24252 avoid overflows by not performing the addition\n                # in offset.apply unless we have to\n                break\n\n            # faster than cur + offset\n            next_date = offset._apply(cur)\n            next_date = next_date.as_unit(unit)\n            if next_date <= cur:\n                raise ValueError(f"Offset {offset} did not increment date")\n            cur = next_date\n    else:\n        while cur >= end:\n            yield cur\n\n            if cur == end:\n                # GH#24252 avoid overflows by not performing the addition\n                # in offset.apply unless we have to\n                break\n\n            # faster than cur + offset\n            next_date = offset._apply(cur)\n            next_date = next_date.as_unit(unit)\n            if next_date >= cur:\n                raise ValueError(f"Offset {offset} did not decrement date")\n            cur = next_date\n',
            'pandas/tests/indexes/datetimes/test_date_range.py': '"""\ntest date_range, bdate_range construction from the convenience range functions\n"""\n\nfrom datetime import (\n    datetime,\n    time,\n    timedelta,\n)\nimport re\n\nimport numpy as np\nimport pytest\n\nfrom pandas._libs.tslibs import timezones\nfrom pandas._libs.tslibs.offsets import (\n    BDay,\n    CDay,\n    DateOffset,\n    MonthEnd,\n    prefix_mapping,\n)\nfrom pandas.errors import (\n    OutOfBoundsDatetime,\n    Pandas4Warning,\n)\nimport pandas.util._test_decorators as td\n\nimport pandas as pd\nfrom pandas import (\n    DataFrame,\n    DatetimeIndex,\n    Series,\n    Timedelta,\n    Timestamp,\n    bdate_range,\n    date_range,\n    offsets,\n)\nimport pandas._testing as tm\nfrom pandas.core.arrays.datetimes import _generate_range as generate_range\nfrom pandas.tests.indexes.datetimes.test_timezones import (\n    FixedOffset,\n    fixed_off_no_name,\n)\n\nfrom pandas.tseries.holiday import USFederalHolidayCalendar\n\nSTART, END = datetime(2009, 1, 1), datetime(2010, 1, 1)\n\n\ndef _get_expected_range(\n    begin_to_match,\n    end_to_match,\n    both_range,\n    inclusive_endpoints,\n):\n    """Helper to get expected range from a both inclusive range"""\n    left_match = begin_to_match == both_range[0]\n    right_match = end_to_match == both_range[-1]\n\n    if inclusive_endpoints == "left" and right_match:\n        expected_range = both_range[:-1]\n    elif inclusive_endpoints == "right" and left_match:\n        expected_range = both_range[1:]\n    elif inclusive_endpoints == "neither" and left_match and right_match:\n        expected_range = both_range[1:-1]\n    elif inclusive_endpoints == "neither" and right_match:\n        expected_range = both_range[:-1]\n    elif inclusive_endpoints == "neither" and left_match:\n        expected_range = both_range[1:]\n    elif inclusive_endpoints == "both":\n        expected_range = both_range[:]\n    else:\n        expected_range = both_range[:]\n\n    return expected_range\n\n\nclass TestTimestampEquivDateRange:\n    # Older tests in TestTimeSeries constructed their `stamp` objects\n    # using `date_range` instead of the `Timestamp` constructor.\n    # TestTimestampEquivDateRange checks that these are equivalent in the\n    # pertinent cases.\n\n    def test_date_range_timestamp_equiv(self):\n        rng = date_range("20090415", "20090519", tz="US/Eastern")\n        stamp = rng[0]\n\n        ts = Timestamp("20090415", tz="US/Eastern")\n        assert ts == stamp\n\n    def test_date_range_timestamp_equiv_dateutil(self):\n        rng = date_range("20090415", "20090519", tz="dateutil/US/Eastern")\n        stamp = rng[0]\n\n        ts = Timestamp("20090415", tz="dateutil/US/Eastern")\n        assert ts == stamp\n\n    def test_date_range_timestamp_equiv_explicit_pytz(self):\n        pytz = pytest.importorskip("pytz")\n        rng = date_range("20090415", "20090519", tz=pytz.timezone("US/Eastern"))\n        stamp = rng[0]\n\n        ts = Timestamp("20090415", tz=pytz.timezone("US/Eastern"))\n        assert ts == stamp\n\n    @td.skip_if_windows\n    def test_date_range_timestamp_equiv_explicit_dateutil(self):\n        from pandas._libs.tslibs.timezones import dateutil_gettz as gettz\n\n        rng = date_range("20090415", "20090519", tz=gettz("US/Eastern"))\n        stamp = rng[0]\n\n        ts = Timestamp("20090415", tz=gettz("US/Eastern"))\n        assert ts == stamp\n\n    def test_date_range_timestamp_equiv_from_datetime_instance(self):\n        datetime_instance = datetime(2014, 3, 4)\n        # build a timestamp with a frequency, since then it supports\n        # addition/subtraction of integers\n        timestamp_instance = date_range(datetime_instance, periods=1, freq="D")[0]\n\n        ts = Timestamp(datetime_instance)\n        assert ts == timestamp_instance\n\n    def test_date_range_timestamp_equiv_preserve_frequency(self):\n        timestamp_instance = date_range("2014-03-05", periods=1, freq="D")[0]\n        ts = Timestamp("2014-03-05")\n\n        assert timestamp_instance == ts\n\n\nclass TestDateRanges:\n    def test_date_range_name(self):\n        idx = date_range(start="2000-01-01", periods=1, freq="YE", name="TEST")\n        assert idx.name == "TEST"\n\n    def test_date_range_invalid_periods(self):\n        msg = "periods must be an integer, got foo"\n        with pytest.raises(TypeError, match=msg):\n            date_range(start="1/1/2000", periods="foo", freq="D")\n\n    def test_date_range_fractional_period(self):\n        msg = "periods must be an integer"\n        with pytest.raises(TypeError, match=msg):\n            date_range("1/1/2000", periods=10.5)\n\n    @pytest.mark.parametrize("freq", ["2M", "1m", "2SM", "2BQ", "1bq", "2BY"])\n    def test_date_range_frequency_M_SM_BQ_BY_raises(self, freq):\n        msg = f"Invalid frequency: {freq}"\n\n        with pytest.raises(ValueError, match=msg):\n            date_range("1/1/2000", periods=4, freq=freq)\n\n    def test_date_range_tuple_freq_raises(self):\n        # GH#34703\n        edate = datetime(2000, 1, 1)\n        with pytest.raises(TypeError, match="pass as a string instead"):\n            date_range(end=edate, freq=("D", 5), periods=20)\n\n    @pytest.mark.parametrize("freq", ["ns", "us", "ms", "min", "s", "h", "D"])\n    def test_date_range_edges(self, freq):\n        # GH#13672\n        td = Timedelta(f"1{freq}")\n        ts = Timestamp("1970-01-01")\n        exp_dtype = "M8[us]" if freq != "ns" else "M8[ns]"\n\n        idx = date_range(\n            start=ts + td,\n            end=ts + 4 * td,\n            freq=freq,\n        )\n        exp = DatetimeIndex(\n            [ts + n * td for n in range(1, 5)],\n            dtype=exp_dtype,\n            freq=freq,\n        )\n        tm.assert_index_equal(idx, exp)\n\n        # start after end\n        idx = date_range(\n            start=ts + 4 * td,\n            end=ts + td,\n            freq=freq,\n        )\n        exp = DatetimeIndex([], dtype=exp_dtype, freq=freq)\n        tm.assert_index_equal(idx, exp)\n\n        # start matches end\n        idx = date_range(\n            start=ts + td,\n            end=ts + td,\n            freq=freq,\n        )\n        exp = DatetimeIndex([ts + td], dtype=exp_dtype, freq=freq)\n        tm.assert_index_equal(idx, exp)\n\n    def test_date_range_near_implementation_bound(self):\n        # GH#???\n        freq = Timedelta(1)\n\n        with pytest.raises(OutOfBoundsDatetime, match="Cannot generate range with"):\n            date_range(end=Timestamp.min, periods=2, freq=freq)\n\n    def test_date_range_nat(self):\n        # GH#11587\n        msg = "Neither `start` nor `end` can be NaT"\n        with pytest.raises(ValueError, match=msg):\n            date_range(start="2016-01-01", end=pd.NaT, freq="D")\n        with pytest.raises(ValueError, match=msg):\n            date_range(start=pd.NaT, end="2016-01-01", freq="D")\n\n    def test_date_range_multiplication_overflow(self):\n        # GH#24255\n        # check that overflows in calculating `addend = periods * stride`\n        #  are caught\n        with tm.assert_produces_warning(None):\n            # we should _not_ be seeing an overflow RuntimeWarning\n            dti = date_range(start="1677-09-22", periods=213503, freq="D")\n\n        assert dti[0] == Timestamp("1677-09-22")\n        assert len(dti) == 213503\n\n        msg = "Cannot generate range with"\n        with pytest.raises(OutOfBoundsDatetime, match=msg):\n            date_range("1969-05-04", periods=200000000, freq="30000D")\n\n    def test_date_range_unsigned_overflow_handling(self):\n        # GH#24255\n        # case where `addend = periods * stride` overflows int64 bounds\n        #  but not uint64 bounds\n        dti = date_range(start="1677-09-22", end="2262-04-11", freq="D")\n\n        dti2 = date_range(start=dti[0], periods=len(dti), freq="D")\n        assert dti2.equals(dti)\n\n        dti3 = date_range(end=dti[-1], periods=len(dti), freq="D")\n        assert dti3.equals(dti)\n\n    def test_date_range_int64_overflow_non_recoverable(self):\n        # GH#24255\n        # case with start later than 1970-01-01, overflow int64 but not uint64\n        msg = "Cannot generate range with"\n        with pytest.raises(OutOfBoundsDatetime, match=msg):\n            date_range(start="1970-02-01", periods=106752 * 24, freq="h", unit="ns")\n\n        # case with end before 1970-01-01, overflow int64 but not uint64\n        with pytest.raises(OutOfBoundsDatetime, match=msg):\n            date_range(end="1969-11-14", periods=106752 * 24, freq="h", unit="ns")\n\n    @pytest.mark.slow\n    @pytest.mark.parametrize(\n        "s_ts, e_ts", [("2262-02-23", "1969-11-14"), ("1970-02-01", "1677-10-22")]\n    )\n    def test_date_range_int64_overflow_stride_endpoint_different_signs(\n        self, s_ts, e_ts\n    ):\n        # cases where stride * periods overflow int64 and stride/endpoint\n        #  have different signs\n        start = Timestamp(s_ts)\n        end = Timestamp(e_ts)\n\n        expected = date_range(start=start, end=end, freq="-1h")\n        assert expected[0] == start\n        assert expected[-1] == end\n\n        dti = date_range(end=end, periods=len(expected), freq="-1h")\n        tm.assert_index_equal(dti, expected)\n\n    def test_date_range_out_of_bounds(self):\n        # GH#14187\n        msg = "Cannot generate range"\n        with pytest.raises(OutOfBoundsDatetime, match=msg):\n            date_range("2016-01-01", periods=100000, freq="D", unit="ns")\n        with pytest.raises(OutOfBoundsDatetime, match=msg):\n            date_range(end="1763-10-12", periods=100000, freq="D", unit="ns")\n\n    def test_date_range_gen_error(self):\n        rng = date_range("1/1/2000 00:00", "1/1/2000 00:18", freq="5min")\n        assert len(rng) == 4\n\n    def test_date_range_normalize(self):\n        snap = datetime.today()\n        n = 50\n\n        rng = date_range(snap, periods=n, normalize=False, freq="2D")\n\n        offset = timedelta(2)\n        expected = DatetimeIndex(\n            [snap + i * offset for i in range(n)], dtype="M8[us]", freq=offset\n        )\n\n        tm.assert_index_equal(rng, expected)\n\n        rng = date_range("1/1/2000 08:15", periods=n, normalize=False, freq="B")\n        the_time = time(8, 15)\n        for val in rng:\n            assert val.time() == the_time\n\n    def test_date_range_ambiguous_arguments(self):\n        # #2538\n        start = datetime(2011, 1, 1, 5, 3, 40)\n        end = datetime(2011, 1, 1, 8, 9, 40)\n\n        msg = (\n            "Of the four parameters: start, end, periods, and "\n            "freq, exactly three must be specified"\n        )\n        with pytest.raises(ValueError, match=msg):\n            date_range(start, end, periods=10, freq="s")\n\n    def test_date_range_convenience_periods(self, unit):\n        # GH 20808\n        result = date_range("2018-04-24", "2018-04-27", periods=3, unit=unit)\n        expected = DatetimeIndex(\n            ["2018-04-24 00:00:00", "2018-04-25 12:00:00", "2018-04-27 00:00:00"],\n            dtype=f"M8[{unit}]",\n            freq=None,\n        )\n\n        tm.assert_index_equal(result, expected)\n\n        # Test if spacing remains linear if tz changes to dst in range\n        result = date_range(\n            "2018-04-01 01:00:00",\n            "2018-04-01 04:00:00",\n            tz="Australia/Sydney",\n            periods=3,\n            unit=unit,\n        )\n        expected = DatetimeIndex(\n            [\n                Timestamp("2018-04-01 01:00:00+1100", tz="Australia/Sydney"),\n                Timestamp("2018-04-01 02:00:00+1000", tz="Australia/Sydney"),\n                Timestamp("2018-04-01 04:00:00+1000", tz="Australia/Sydney"),\n            ]\n        ).as_unit(unit)\n        tm.assert_index_equal(result, expected)\n\n    def test_date_range_index_comparison(self):\n        rng = date_range("2011-01-01", periods=3, tz="US/Eastern")\n        df = Series(rng).to_frame()\n        arr = np.array([rng.to_list()]).T\n        arr2 = np.array([rng]).T\n\n        with pytest.raises(ValueError, match="Unable to coerce to Series"):\n            rng == df\n\n        with pytest.raises(ValueError, match="Unable to coerce to Series"):\n            df == rng\n\n        expected = DataFrame([True, True, True])\n\n        results = df == arr2\n        tm.assert_frame_equal(results, expected)\n\n        expected = Series([True, True, True], name=0)\n\n        results = df[0] == arr2[:, 0]\n        tm.assert_series_equal(results, expected)\n\n        expected = np.array(\n            [[True, False, False], [False, True, False], [False, False, True]]\n        )\n        results = rng == arr\n        tm.assert_numpy_array_equal(results, expected)\n\n    @pytest.mark.parametrize(\n        "start,end,result_tz",\n        [\n            ["20180101", "20180103", "US/Eastern"],\n            [datetime(2018, 1, 1), datetime(2018, 1, 3), "US/Eastern"],\n            [Timestamp("20180101"), Timestamp("20180103"), "US/Eastern"],\n            [\n                Timestamp("20180101", tz="US/Eastern"),\n                Timestamp("20180103", tz="US/Eastern"),\n                "US/Eastern",\n            ],\n            [\n                Timestamp("20180101", tz="US/Eastern"),\n                Timestamp("20180103", tz="US/Eastern"),\n                None,\n            ],\n        ],\n    )\n    def test_date_range_linspacing_tz(self, start, end, result_tz):\n        # GH 20983\n        result = date_range(start, end, periods=3, tz=result_tz)\n        expected = date_range("20180101", periods=3, freq="D", tz="US/Eastern")\n        tm.assert_index_equal(result, expected)\n\n    def test_date_range_timedelta(self):\n        start = "2020-01-01"\n        end = "2020-01-11"\n        rng1 = date_range(start, end, freq="3D")\n        rng2 = date_range(start, end, freq=timedelta(days=3))\n        tm.assert_index_equal(rng1, rng2)\n\n    def test_range_misspecified(self):\n        # GH #1095\n        msg = (\n            "Of the four parameters: start, end, periods, and "\n            "freq, exactly three must be specified"\n        )\n\n        with pytest.raises(ValueError, match=msg):\n            date_range(start="1/1/2000")\n\n        with pytest.raises(ValueError, match=msg):\n            date_range(end="1/1/2000")\n\n        with pytest.raises(ValueError, match=msg):\n            date_range(periods=10)\n\n        with pytest.raises(ValueError, match=msg):\n            date_range(start="1/1/2000", freq="h")\n\n        with pytest.raises(ValueError, match=msg):\n            date_range(end="1/1/2000", freq="h")\n\n        with pytest.raises(ValueError, match=msg):\n            date_range(periods=10, freq="h")\n\n        with pytest.raises(ValueError, match=msg):\n            date_range()\n\n    def test_compat_replace(self):\n        # https://github.com/statsmodels/statsmodels/issues/3349\n        # replace should take ints/longs for compat\n        result = date_range(Timestamp("1960-04-01 00:00:00"), periods=76, freq="QS-JAN")\n        assert len(result) == 76\n\n    def test_catch_infinite_loop(self):\n        offset = offsets.DateOffset(minute=5)\n        # blow up, don\'t loop forever\n        msg = "Offset <DateOffset: minute=5> did not increment date"\n        with pytest.raises(ValueError, match=msg):\n            date_range(datetime(2011, 11, 11), datetime(2011, 11, 12), freq=offset)\n\n    def test_construct_over_dst(self, unit):\n        # GH 20854\n        pre_dst = Timestamp("2010-11-07 01:00:00").tz_localize(\n            "US/Pacific", ambiguous=True\n        )\n        pst_dst = Timestamp("2010-11-07 01:00:00").tz_localize(\n            "US/Pacific", ambiguous=False\n        )\n        expect_data = [\n            Timestamp("2010-11-07 00:00:00", tz="US/Pacific"),\n            pre_dst,\n            pst_dst,\n        ]\n        expected = DatetimeIndex(expect_data, freq="h").as_unit(unit)\n        result = date_range(\n            start="2010-11-7", periods=3, freq="h", tz="US/Pacific", unit=unit\n        )\n        tm.assert_index_equal(result, expected)\n\n    def test_construct_with_different_start_end_string_format(self, unit):\n        # GH 12064\n        result = date_range(\n            "2013-01-01 00:00:00+09:00",\n            "2013/01/01 02:00:00+09:00",\n            freq="h",\n            unit=unit,\n        )\n        expected = DatetimeIndex(\n            [\n                Timestamp("2013-01-01 00:00:00+09:00"),\n                Timestamp("2013-01-01 01:00:00+09:00"),\n                Timestamp("2013-01-01 02:00:00+09:00"),\n            ],\n            freq="h",\n        ).as_unit(unit)\n        tm.assert_index_equal(result, expected)\n\n    def test_error_with_zero_monthends(self):\n        msg = r"Offset <0 \\* MonthEnds> did not increment date"\n        with pytest.raises(ValueError, match=msg):\n            date_range("1/1/2000", "1/1/2001", freq=MonthEnd(0))\n\n    def test_range_bug(self, unit):\n        # GH #770\n        offset = DateOffset(months=3)\n        result = date_range("2011-1-1", "2012-1-31", freq=offset, unit=unit)\n\n        start = datetime(2011, 1, 1)\n        expected = DatetimeIndex(\n            [start + i * offset for i in range(5)], dtype=f"M8[{unit}]", freq=offset\n        )\n        tm.assert_index_equal(result, expected)\n\n    def test_range_tz_pytz(self):\n        # see gh-2906\n        pytz = pytest.importorskip("pytz")\n        tz = pytz.timezone("US/Eastern")\n        start = tz.localize(datetime(2011, 1, 1))\n        end = tz.localize(datetime(2011, 1, 3))\n\n        dr = date_range(start=start, periods=3)\n        assert dr.tz.zone == tz.zone\n        assert dr[0] == start\n        assert dr[2] == end\n\n        dr = date_range(end=end, periods=3)\n        assert dr.tz.zone == tz.zone\n        assert dr[0] == start\n        assert dr[2] == end\n\n        dr = date_range(start=start, end=end)\n        assert dr.tz.zone == tz.zone\n        assert dr[0] == start\n        assert dr[2] == end\n\n    @pytest.mark.parametrize(\n        "start, end",\n        [\n            [datetime(2014, 3, 6), datetime(2014, 3, 12)],\n            [datetime(2013, 11, 1), datetime(2013, 11, 6)],\n        ],\n    )\n    def test_range_tz_dst_straddle_pytz(self, start, end):\n        pytz = pytest.importorskip("pytz")\n        tz = pytz.timezone("US/Eastern")\n        start = Timestamp(start, tz=tz)\n        end = Timestamp(end, tz=tz)\n        dr = date_range(start, end, freq="D")\n        assert dr[0] == start\n        assert dr[-1] == end\n        assert np.all(dr.hour == 0)\n\n        dr = date_range(start, end, freq="D", tz=tz)\n        assert dr[0] == start\n        assert dr[-1] == end\n        assert np.all(dr.hour == 0)\n\n        dr = date_range(\n            start.replace(tzinfo=None),\n            end.replace(tzinfo=None),\n            freq="D",\n            tz=tz,\n        )\n        assert dr[0] == start\n        assert dr[-1] == end\n        assert np.all(dr.hour == 0)\n\n    def test_range_tz_dateutil(self):\n        # see gh-2906\n\n        # Use maybe_get_tz to fix filename in tz under dateutil.\n        from pandas._libs.tslibs.timezones import maybe_get_tz\n\n        tz = lambda x: maybe_get_tz("dateutil/" + x)\n\n        start = datetime(2011, 1, 1, tzinfo=tz("US/Eastern"))\n        end = datetime(2011, 1, 3, tzinfo=tz("US/Eastern"))\n\n        dr = date_range(start=start, periods=3)\n        assert dr.tz == tz("US/Eastern")\n        assert dr[0] == start\n        assert dr[2] == end\n\n        dr = date_range(end=end, periods=3)\n        assert dr.tz == tz("US/Eastern")\n        assert dr[0] == start\n        assert dr[2] == end\n\n        dr = date_range(start=start, end=end)\n        assert dr.tz == tz("US/Eastern")\n        assert dr[0] == start\n        assert dr[2] == end\n\n    @pytest.mark.parametrize("freq", ["1D", "3D", "2ME", "7W", "3h", "YE"])\n    @pytest.mark.parametrize("tz", [None, "US/Eastern"])\n    def test_range_closed(self, freq, tz, inclusive_endpoints_fixture):\n        # GH#12409, GH#12684\n\n        begin = Timestamp("2011/1/1", tz=tz)\n        end = Timestamp("2014/1/1", tz=tz)\n\n        result_range = date_range(\n            begin, end, inclusive=inclusive_endpoints_fixture, freq=freq\n        )\n        both_range = date_range(begin, end, inclusive="both", freq=freq)\n        expected_range = _get_expected_range(\n            begin, end, both_range, inclusive_endpoints_fixture\n        )\n\n        tm.assert_index_equal(expected_range, result_range)\n\n    @pytest.mark.parametrize("freq", ["1D", "3D", "2ME", "7W", "3h", "YE"])\n    def test_range_with_tz_closed_with_tz_aware_start_end(\n        self, freq, inclusive_endpoints_fixture\n    ):\n        begin = Timestamp("2011/1/1")\n        end = Timestamp("2014/1/1")\n        begintz = Timestamp("2011/1/1", tz="US/Eastern")\n        endtz = Timestamp("2014/1/1", tz="US/Eastern")\n\n        result_range = date_range(\n            begin,\n            end,\n            inclusive=inclusive_endpoints_fixture,\n            freq=freq,\n            tz="US/Eastern",\n        )\n        both_range = date_range(\n            begin, end, inclusive="both", freq=freq, tz="US/Eastern"\n        )\n        expected_range = _get_expected_range(\n            begintz,\n            endtz,\n            both_range,\n            inclusive_endpoints_fixture,\n        )\n\n        tm.assert_index_equal(expected_range, result_range)\n\n    def test_range_closed_boundary(self, inclusive_endpoints_fixture):\n        # GH#11804\n        right_boundary = date_range(\n            "2015-09-12",\n            "2015-12-01",\n            freq="QS-MAR",\n            inclusive=inclusive_endpoints_fixture,\n        )\n        left_boundary = date_range(\n            "2015-09-01",\n            "2015-09-12",\n            freq="QS-MAR",\n            inclusive=inclusive_endpoints_fixture,\n        )\n        both_boundary = date_range(\n            "2015-09-01",\n            "2015-12-01",\n            freq="QS-MAR",\n            inclusive=inclusive_endpoints_fixture,\n        )\n        neither_boundary = date_range(\n            "2015-09-11",\n            "2015-09-12",\n            freq="QS-MAR",\n            inclusive=inclusive_endpoints_fixture,\n        )\n\n        expected_right = both_boundary\n        expected_left = both_boundary\n        expected_both = both_boundary\n\n        if inclusive_endpoints_fixture == "right":\n            expected_left = both_boundary[1:]\n        elif inclusive_endpoints_fixture == "left":\n            expected_right = both_boundary[:-1]\n        elif inclusive_endpoints_fixture == "both":\n            expected_right = both_boundary[1:]\n            expected_left = both_boundary[:-1]\n\n        expected_neither = both_boundary[1:-1]\n\n        tm.assert_index_equal(right_boundary, expected_right)\n        tm.assert_index_equal(left_boundary, expected_left)\n        tm.assert_index_equal(both_boundary, expected_both)\n        tm.assert_index_equal(neither_boundary, expected_neither)\n\n    def test_date_range_years_only(self, tz_naive_fixture):\n        tz = tz_naive_fixture\n        # GH#6961\n        rng1 = date_range("2014", "2015", freq="ME", tz=tz)\n        expected1 = date_range("2014-01-31", "2014-12-31", freq="ME", tz=tz)\n        tm.assert_index_equal(rng1, expected1)\n\n        rng2 = date_range("2014", "2015", freq="MS", tz=tz)\n        expected2 = date_range("2014-01-01", "2015-01-01", freq="MS", tz=tz)\n        tm.assert_index_equal(rng2, expected2)\n\n        rng3 = date_range("2014", "2020", freq="YE", tz=tz)\n        expected3 = date_range("2014-12-31", "2019-12-31", freq="YE", tz=tz)\n        tm.assert_index_equal(rng3, expected3)\n\n        rng4 = date_range("2014", "2020", freq="YS", tz=tz)\n        expected4 = date_range("2014-01-01", "2020-01-01", freq="YS", tz=tz)\n        tm.assert_index_equal(rng4, expected4)\n\n    def test_freq_divides_end_in_nanos(self):\n        # GH 10885\n        result_1 = date_range("2005-01-12 10:00", "2005-01-12 16:00", freq="345min")\n        result_2 = date_range("2005-01-13 10:00", "2005-01-13 16:00", freq="345min")\n        expected_1 = DatetimeIndex(\n            ["2005-01-12 10:00:00", "2005-01-12 15:45:00"],\n            dtype="datetime64[us]",\n            freq="345min",\n            tz=None,\n        )\n        expected_2 = DatetimeIndex(\n            ["2005-01-13 10:00:00", "2005-01-13 15:45:00"],\n            dtype="datetime64[us]",\n            freq="345min",\n            tz=None,\n        )\n        tm.assert_index_equal(result_1, expected_1)\n        tm.assert_index_equal(result_2, expected_2)\n\n    def test_cached_range_bug(self):\n        rng = date_range("2010-09-01 05:00:00", periods=50, freq=DateOffset(hours=6))\n        assert len(rng) == 50\n        assert rng[0] == datetime(2010, 9, 1, 5)\n\n    def test_timezone_comparison_bug(self):\n        # smoke test\n        start = Timestamp("20130220 10:00", tz="US/Eastern")\n        result = date_range(start, periods=2, tz="US/Eastern")\n        assert len(result) == 2\n\n    def test_timezone_comparison_assert(self):\n        start = Timestamp("20130220 10:00", tz="US/Eastern")\n        msg = "Inferred time zone not equal to passed time zone"\n        with pytest.raises(AssertionError, match=msg):\n            date_range(start, periods=2, tz="Europe/Berlin")\n\n    def test_negative_non_tick_frequency_descending_dates(self, tz_aware_fixture):\n        # GH 23270\n        tz = tz_aware_fixture\n        result = date_range(start="2011-06-01", end="2011-01-01", freq="-1MS", tz=tz)\n        expected = date_range(end="2011-06-01", start="2011-01-01", freq="1MS", tz=tz)[\n            ::-1\n        ]\n        tm.assert_index_equal(result, expected)\n\n    def test_range_where_start_equal_end(self, inclusive_endpoints_fixture):\n        # GH 43394\n        start = "2021-09-02"\n        end = "2021-09-02"\n        result = date_range(\n            start=start, end=end, freq="D", inclusive=inclusive_endpoints_fixture\n        )\n\n        both_range = date_range(start=start, end=end, freq="D", inclusive="both")\n        if inclusive_endpoints_fixture == "neither":\n            expected = both_range[1:-1]\n        elif inclusive_endpoints_fixture in ("left", "right", "both"):\n            expected = both_range[:]\n\n        tm.assert_index_equal(result, expected)\n\n    def test_freq_dateoffset_with_relateivedelta_nanos(self):\n        # GH 46877\n        freq = DateOffset(hours=10, days=57, nanoseconds=3)\n        result = date_range(end="1970-01-01 00:00:00", periods=10, freq=freq, name="a")\n        expected = DatetimeIndex(\n            [\n                "1968-08-02T05:59:59.999999973",\n                "1968-09-28T15:59:59.999999976",\n                "1968-11-25T01:59:59.999999979",\n                "1969-01-21T11:59:59.999999982",\n                "1969-03-19T21:59:59.999999985",\n                "1969-05-16T07:59:59.999999988",\n                "1969-07-12T17:59:59.999999991",\n                "1969-09-08T03:59:59.999999994",\n                "1969-11-04T13:59:59.999999997",\n                "1970-01-01T00:00:00.000000000",\n            ],\n            name="a",\n        )\n        tm.assert_index_equal(result, expected)\n\n    @pytest.mark.parametrize("freq", ["2T", "2L", "1l", "1U", "2N", "2n"])\n    def test_frequency_H_T_S_L_U_N_raises(self, freq):\n        msg = f"Invalid frequency: {freq}"\n        with pytest.raises(ValueError, match=msg):\n            date_range("1/1/2000", periods=2, freq=freq)\n\n    @pytest.mark.parametrize(\n        "freq_depr", ["m", "bm", "CBM", "SM", "BQ", "q-feb", "y-may", "Y-MAY"]\n    )\n    def test_frequency_raises(self, freq_depr):\n        msg = f"Invalid frequency: {freq_depr}"\n\n        with pytest.raises(ValueError, match=msg):\n            date_range("1/1/2000", periods=2, freq=freq_depr)\n\n    def test_date_range_bday(self):\n        sdate = datetime(1999, 12, 25)\n        idx = date_range(start=sdate, freq="1B", periods=20)\n        assert len(idx) == 20\n        assert idx[0] == sdate + 0 * offsets.BDay()\n        assert idx.freq == "B"\n\n    @pytest.mark.parametrize("freq", ["200A", "2A-MAY"])\n    def test_frequency_A_raises(self, freq):\n        freq_msg = re.split("[0-9]*", freq, maxsplit=1)[1]\n        msg = f"Invalid frequency: {freq_msg}"\n\n        with pytest.raises(ValueError, match=msg):\n            date_range("1/1/2000", periods=2, freq=freq)\n\n    @pytest.mark.parametrize(\n        "freq,freq_depr",\n        [\n            ("2W", "2w"),\n            ("2W-WED", "2w-wed"),\n            ("2B", "2b"),\n            ("2D", "2d"),\n            ("2C", "2c"),\n        ],\n    )\n    def test_date_range_depr_lowercase_frequency(self, freq, freq_depr):\n        # GH#58998\n        depr_msg = (\n            f"\'{freq_depr[1:]}\' is deprecated and will be removed in a future version."\n        )\n\n        expected = date_range("1/1/2000", periods=4, freq=freq)\n        with tm.assert_produces_warning(Pandas4Warning, match=depr_msg):\n            result = date_range("1/1/2000", periods=4, freq=freq_depr)\n        tm.assert_index_equal(result, expected)\n\n    @pytest.mark.parametrize(\n        "freq_removed,freq",\n        [\n            ("100A", "Y"),\n            ("2A-DEC", "Y-DEC"),\n            ("100AS", "YS"),\n            ("2AS-MAY", "YS-MAY"),\n        ],\n    )\n    def test_error_message_for_removed_year_yearbegin_frequencies(\n        self, freq, freq_removed\n    ):\n        msg = f"Did you mean {freq}"\n        with pytest.raises(ValueError, match=msg):\n            date_range("1/1/2000", periods=2, freq=freq_removed)\n\n\nclass TestDateRangeTZ:\n    """Tests for date_range with timezones"""\n\n    def test_hongkong_tz_convert(self):\n        # GH#1673 smoke test\n        dr = date_range("2012-01-01", "2012-01-10", freq="D", tz="Hongkong")\n\n        # it works!\n        dr.hour\n\n    @pytest.mark.parametrize("tzstr", ["US/Eastern", "dateutil/US/Eastern"])\n    def test_date_range_span_dst_transition(self, tzstr):\n        # GH#1778\n\n        # Standard -> Daylight Savings Time\n        dr = date_range("03/06/2012 00:00", periods=200, freq="W-FRI", tz="US/Eastern")\n\n        assert (dr.hour == 0).all()\n\n        dr = date_range("2012-11-02", periods=10, tz=tzstr)\n        result = dr.hour\n        expected = pd.Index([0] * 10, dtype="int32")\n        tm.assert_index_equal(result, expected)\n\n    @pytest.mark.parametrize("tzstr", ["US/Eastern", "dateutil/US/Eastern"])\n    def test_date_range_timezone_str_argument(self, tzstr):\n        tz = timezones.maybe_get_tz(tzstr)\n        result = date_range("1/1/2000", periods=10, tz=tzstr)\n        expected = date_range("1/1/2000", periods=10, tz=tz)\n\n        tm.assert_index_equal(result, expected)\n\n    def test_date_range_with_fixed_tz(self):\n        off = FixedOffset(420, "+07:00")\n        start = datetime(2012, 3, 11, 5, 0, 0, tzinfo=off)\n        end = datetime(2012, 6, 11, 5, 0, 0, tzinfo=off)\n        rng = date_range(start=start, end=end)\n        assert off == rng.tz\n\n        rng2 = date_range(start, periods=len(rng), tz=off)\n        tm.assert_index_equal(rng, rng2)\n\n        rng3 = date_range("3/11/2012 05:00:00+07:00", "6/11/2012 05:00:00+07:00")\n        assert (rng.values == rng3.values).all()\n\n    def test_date_range_with_fixedoffset_noname(self):\n        off = fixed_off_no_name\n        start = datetime(2012, 3, 11, 5, 0, 0, tzinfo=off)\n        end = datetime(2012, 6, 11, 5, 0, 0, tzinfo=off)\n        rng = date_range(start=start, end=end)\n        assert off == rng.tz\n\n        idx = pd.Index([start, end])\n        assert off == idx.tz\n\n    @pytest.mark.parametrize("tzstr", ["US/Eastern", "dateutil/US/Eastern"])\n    def test_date_range_with_tz(self, tzstr):\n        stamp = Timestamp("3/11/2012 05:00", tz=tzstr)\n        assert stamp.hour == 5\n\n        rng = date_range("3/11/2012 04:00", periods=10, freq="h", tz=tzstr)\n\n        assert stamp == rng[1]\n\n    @pytest.mark.parametrize("tz", ["Europe/London", "dateutil/Europe/London"])\n    def test_date_range_ambiguous_endpoint(self, tz):\n        # construction with an ambiguous end-point\n        # GH#11626\n\n        with pytest.raises(ValueError, match="Cannot infer dst time"):\n            date_range(\n                "2013-10-26 23:00", "2013-10-27 01:00", tz="Europe/London", freq="h"\n            )\n\n        times = date_range(\n            "2013-10-26 23:00", "2013-10-27 01:00", freq="h", tz=tz, ambiguous="infer"\n        )\n        assert times[0] == Timestamp("2013-10-26 23:00", tz=tz)\n        assert times[-1] == Timestamp("2013-10-27 01:00:00+0000", tz=tz)\n\n    @pytest.mark.parametrize(\n        "tz, option, expected",\n        [\n            ["US/Pacific", "shift_forward", "2019-03-10 03:00"],\n            ["dateutil/US/Pacific", "shift_forward", "2019-03-10 03:00"],\n            ["US/Pacific", "shift_backward", "2019-03-10 01:00"],\n            ["dateutil/US/Pacific", "shift_backward", "2019-03-10 01:00"],\n            ["US/Pacific", timedelta(hours=1), "2019-03-10 03:00"],\n        ],\n    )\n    def test_date_range_nonexistent_endpoint(self, tz, option, expected):\n        # construction with an nonexistent end-point\n\n        with pytest.raises(ValueError, match="2019-03-10 02:00:00"):\n            date_range(\n                "2019-03-10 00:00", "2019-03-10 02:00", tz="US/Pacific", freq="h"\n            )\n\n        times = date_range(\n            "2019-03-10 00:00", "2019-03-10 02:00", freq="h", tz=tz, nonexistent=option\n        )\n        assert times[-1] == Timestamp(expected, tz=tz)\n\n\nclass TestGenRangeGeneration:\n    @pytest.mark.parametrize(\n        "freqstr,offset",\n        [\n            ("B", BDay()),\n            ("C", CDay()),\n        ],\n    )\n    def test_generate(self, freqstr, offset):\n        rng1 = list(generate_range(START, END, periods=None, offset=offset, unit="ns"))\n        rng2 = list(generate_range(START, END, periods=None, offset=freqstr, unit="ns"))\n        assert rng1 == rng2\n\n    def test_1(self):\n        rng = list(\n            generate_range(\n                start=datetime(2009, 3, 25),\n                end=None,\n                periods=2,\n                offset=BDay(),\n                unit="ns",\n            )\n        )\n        expected = [datetime(2009, 3, 25), datetime(2009, 3, 26)]\n        assert rng == expected\n\n    def test_2(self):\n        rng = list(\n            generate_range(\n                start=datetime(2008, 1, 1),\n                end=datetime(2008, 1, 3),\n                periods=None,\n                offset=BDay(),\n                unit="ns",\n            )\n        )\n        expected = [datetime(2008, 1, 1), datetime(2008, 1, 2), datetime(2008, 1, 3)]\n        assert rng == expected\n\n    def test_3(self):\n        rng = list(\n            generate_range(\n                start=datetime(2008, 1, 5),\n                end=datetime(2008, 1, 6),\n                periods=None,\n                offset=BDay(),\n                unit="ns",\n            )\n        )\n        expected = []\n        assert rng == expected\n\n    def test_precision_finer_than_offset(self):\n        # GH#9907\n        result1 = date_range(\n            start="2015-04-15 00:00:03", end="2016-04-22 00:00:00", freq="QE"\n        )\n        result2 = date_range(\n            start="2015-04-15 00:00:03", end="2015-06-22 00:00:04", freq="W"\n        )\n        expected1_list = [\n            "2015-06-30 00:00:03",\n            "2015-09-30 00:00:03",\n            "2015-12-31 00:00:03",\n            "2016-03-31 00:00:03",\n        ]\n        expected2_list = [\n            "2015-04-19 00:00:03",\n            "2015-04-26 00:00:03",\n            "2015-05-03 00:00:03",\n            "2015-05-10 00:00:03",\n            "2015-05-17 00:00:03",\n            "2015-05-24 00:00:03",\n            "2015-05-31 00:00:03",\n            "2015-06-07 00:00:03",\n            "2015-06-14 00:00:03",\n            "2015-06-21 00:00:03",\n        ]\n        expected1 = DatetimeIndex(\n            expected1_list, dtype="datetime64[us]", freq="QE-DEC", tz=None\n        )\n        expected2 = DatetimeIndex(\n            expected2_list, dtype="datetime64[us]", freq="W-SUN", tz=None\n        )\n        tm.assert_index_equal(result1, expected1)\n        tm.assert_index_equal(result2, expected2)\n\n    dt1, dt2 = "2017-01-01", "2017-01-01"\n    tz1, tz2 = "US/Eastern", "Europe/London"\n\n    @pytest.mark.parametrize(\n        "start,end",\n        [\n            (Timestamp(dt1, tz=tz1), Timestamp(dt2)),\n            (Timestamp(dt1), Timestamp(dt2, tz=tz2)),\n            (Timestamp(dt1, tz=tz1), Timestamp(dt2, tz=tz2)),\n            (Timestamp(dt1, tz=tz2), Timestamp(dt2, tz=tz1)),\n        ],\n    )\n    def test_mismatching_tz_raises_err(self, start, end):\n        # issue 18488\n        msg = "Start and end cannot both be tz-aware with different timezones"\n        with pytest.raises(TypeError, match=msg):\n            date_range(start, end)\n        with pytest.raises(TypeError, match=msg):\n            date_range(start, end, freq=BDay())\n\n\nclass TestBusinessDateRange:\n    def test_constructor(self):\n        bdate_range(START, END, freq=BDay())\n        bdate_range(START, periods=20, freq=BDay())\n        bdate_range(end=START, periods=20, freq=BDay())\n\n        msg = "periods must be an integer, got B"\n        with pytest.raises(TypeError, match=msg):\n            date_range("2011-1-1", "2012-1-1", "B")\n\n        with pytest.raises(TypeError, match=msg):\n            bdate_range("2011-1-1", "2012-1-1", "B")\n\n        msg = "freq must be specified for bdate_range; use date_range instead"\n        with pytest.raises(TypeError, match=msg):\n            bdate_range(START, END, periods=10, freq=None)\n\n    def test_misc(self):\n        end = datetime(2009, 5, 13)\n        dr = bdate_range(end=end, periods=20)\n        firstDate = end - 19 * BDay()\n\n        assert len(dr) == 20\n        assert dr[0] == firstDate\n        assert dr[-1] == end\n\n    def test_date_parse_failure(self):\n        badly_formed_date = "2007/100/1"\n\n        msg = "Unknown datetime string format, unable to parse: 2007/100/1"\n        with pytest.raises(ValueError, match=msg):\n            Timestamp(badly_formed_date)\n\n        with pytest.raises(ValueError, match=msg):\n            bdate_range(start=badly_formed_date, periods=10)\n\n        with pytest.raises(ValueError, match=msg):\n            bdate_range(end=badly_formed_date, periods=10)\n\n        with pytest.raises(ValueError, match=msg):\n            bdate_range(badly_formed_date, badly_formed_date)\n\n    def test_daterange_bug_456(self):\n        # GH #456\n        rng1 = bdate_range("12/5/2011", "12/5/2011")\n        rng2 = bdate_range("12/2/2011", "12/5/2011")\n        assert rng2._data.freq == BDay()\n\n        result = rng1.union(rng2)\n        assert isinstance(result, DatetimeIndex)\n\n    def test_bdays_and_open_boundaries(self, inclusive_endpoints_fixture):\n        # GH 6673\n        start = "2018-07-21"  # Saturday\n        end = "2018-07-29"  # Sunday\n        result = date_range(start, end, freq="B", inclusive=inclusive_endpoints_fixture)\n\n        bday_start = "2018-07-23"  # Monday\n        bday_end = "2018-07-27"  # Friday\n        expected = date_range(bday_start, bday_end, freq="D")\n        tm.assert_index_equal(result, expected)\n        # Note: we do _not_ expect the freqs to match here\n\n    def test_bday_near_overflow(self):\n        # GH#24252 avoid doing unnecessary addition that _would_ overflow\n        start = Timestamp.max.floor("D").to_pydatetime()\n        rng = date_range(start, end=None, periods=1, freq="B")\n        expected = DatetimeIndex([start], freq="B")\n        tm.assert_index_equal(rng, expected)\n\n    def test_bday_overflow_error(self):\n        # GH#24252 check that we get OutOfBoundsDatetime and not OverflowError\n        msg = "Out of bounds nanosecond timestamp"\n        start = Timestamp.max.floor("D").to_pydatetime()\n        with pytest.raises(OutOfBoundsDatetime, match=msg):\n            date_range(start, periods=2, freq="B", unit="ns")\n\n\nclass TestCustomDateRange:\n    def test_constructor(self):\n        bdate_range(START, END, freq=CDay())\n        bdate_range(START, periods=20, freq=CDay())\n        bdate_range(end=START, periods=20, freq=CDay())\n\n        msg = "periods must be an integer, got C"\n        with pytest.raises(TypeError, match=msg):\n            date_range("2011-1-1", "2012-1-1", "C")\n\n        with pytest.raises(TypeError, match=msg):\n            bdate_range("2011-1-1", "2012-1-1", "C")\n\n    def test_misc(self):\n        end = datetime(2009, 5, 13)\n        dr = bdate_range(end=end, periods=20, freq="C")\n        firstDate = end - 19 * CDay()\n\n        assert len(dr) == 20\n        assert dr[0] == firstDate\n        assert dr[-1] == end\n\n    def test_daterange_bug_456(self):\n        # GH #456\n        rng1 = bdate_range("12/5/2011", "12/5/2011", freq="C")\n        rng2 = bdate_range("12/2/2011", "12/5/2011", freq="C")\n        assert rng2._data.freq == CDay()\n\n        result = rng1.union(rng2)\n        assert isinstance(result, DatetimeIndex)\n\n    def test_cdaterange(self, unit):\n        result = bdate_range("2013-05-01", periods=3, freq="C", unit=unit)\n        expected = DatetimeIndex(\n            ["2013-05-01", "2013-05-02", "2013-05-03"], dtype=f"M8[{unit}]", freq="C"\n        )\n        tm.assert_index_equal(result, expected)\n        assert result.freq == expected.freq\n\n    def test_cdaterange_weekmask(self, unit):\n        result = bdate_range(\n            "2013-05-01", periods=3, freq="C", weekmask="Sun Mon Tue Wed Thu", unit=unit\n        )\n        expected = DatetimeIndex(\n            ["2013-05-01", "2013-05-02", "2013-05-05"],\n            dtype=f"M8[{unit}]",\n            freq=result.freq,\n        )\n        tm.assert_index_equal(result, expected)\n        assert result.freq == expected.freq\n\n        # raise with non-custom freq\n        msg = (\n            "a custom frequency string is required when holidays or "\n            "weekmask are passed, got frequency B"\n        )\n        with pytest.raises(ValueError, match=msg):\n            bdate_range("2013-05-01", periods=3, weekmask="Sun Mon Tue Wed Thu")\n\n    def test_cdaterange_holidays(self, unit):\n        result = bdate_range(\n            "2013-05-01", periods=3, freq="C", holidays=["2013-05-01"], unit=unit\n        )\n        expected = DatetimeIndex(\n            ["2013-05-02", "2013-05-03", "2013-05-06"],\n            dtype=f"M8[{unit}]",\n            freq=result.freq,\n        )\n        tm.assert_index_equal(result, expected)\n        assert result.freq == expected.freq\n\n        # raise with non-custom freq\n        msg = (\n            "a custom frequency string is required when holidays or "\n            "weekmask are passed, got frequency B"\n        )\n        with pytest.raises(ValueError, match=msg):\n            bdate_range("2013-05-01", periods=3, holidays=["2013-05-01"])\n\n    def test_cdaterange_weekmask_and_holidays(self, unit):\n        result = bdate_range(\n            "2013-05-01",\n            periods=3,\n            freq="C",\n            weekmask="Sun Mon Tue Wed Thu",\n            holidays=["2013-05-01"],\n            unit=unit,\n        )\n        expected = DatetimeIndex(\n            ["2013-05-02", "2013-05-05", "2013-05-06"],\n            dtype=f"M8[{unit}]",\n            freq=result.freq,\n        )\n        tm.assert_index_equal(result, expected)\n        assert result.freq == expected.freq\n\n    def test_cdaterange_holidays_weekmask_requires_freqstr(self):\n        # raise with non-custom freq\n        msg = (\n            "a custom frequency string is required when holidays or "\n            "weekmask are passed, got frequency B"\n        )\n        with pytest.raises(ValueError, match=msg):\n            bdate_range(\n                "2013-05-01",\n                periods=3,\n                weekmask="Sun Mon Tue Wed Thu",\n                holidays=["2013-05-01"],\n            )\n\n    @pytest.mark.parametrize(\n        "freq", [freq for freq in prefix_mapping if freq.upper().startswith("C")]\n    )\n    def test_all_custom_freq(self, freq):\n        # should not raise\n        bdate_range(\n            START, END, freq=freq, weekmask="Mon Wed Fri", holidays=["2009-03-14"]\n        )\n\n        bad_freq = freq + "FOO"\n        msg = f"invalid custom frequency string: {bad_freq}"\n        with pytest.raises(ValueError, match=msg):\n            bdate_range(START, END, freq=bad_freq)\n\n    @pytest.mark.parametrize(\n        "start_end",\n        [\n            ("2018-01-01T00:00:01.000Z", "2018-01-03T00:00:01.000Z"),\n            ("2018-01-01T00:00:00.010Z", "2018-01-03T00:00:00.010Z"),\n            ("2001-01-01T00:00:00.010Z", "2001-01-03T00:00:00.010Z"),\n        ],\n    )\n    def test_range_with_millisecond_resolution(self, start_end):\n        # https://github.com/pandas-dev/pandas/issues/24110\n        start, end = start_end\n        result = date_range(start=start, end=end, periods=2, inclusive="left")\n        expected = DatetimeIndex([start], dtype="M8[us, UTC]")\n        tm.assert_index_equal(result, expected)\n\n    @pytest.mark.parametrize(\n        "start,period,expected",\n        [\n            ("2022-07-23 00:00:00+02:00", 1, ["2022-07-25 00:00:00+02:00"]),\n            ("2022-07-22 00:00:00+02:00", 1, ["2022-07-22 00:00:00+02:00"]),\n            (\n                "2022-07-22 00:00:00+02:00",\n                2,\n                ["2022-07-22 00:00:00+02:00", "2022-07-25 00:00:00+02:00"],\n            ),\n        ],\n    )\n    def test_range_with_timezone_and_custombusinessday(self, start, period, expected):\n        # GH49441\n        result = date_range(start=start, periods=period, freq="C")\n        expected = DatetimeIndex(expected).as_unit("us")\n        tm.assert_index_equal(result, expected)\n\n    def test_data_range_custombusinessday_partial_time(self, unit):\n        # GH#57456\n        offset = offsets.CustomBusinessDay(weekmask="Sun Mon Tue")\n        start = datetime(2024, 2, 6, 23)\n        # end datetime is partial and not in the offset\n        end = datetime(2024, 2, 14, 14)\n        result = date_range(start, end, freq=offset, unit=unit)\n        expected = DatetimeIndex(\n            [\n                "2024-02-06 23:00:00",\n                "2024-02-11 23:00:00",\n                "2024-02-12 23:00:00",\n                "2024-02-13 23:00:00",\n            ],\n            dtype=f"M8[{unit}]",\n        )\n        tm.assert_index_equal(result, expected)\n\n    def test_cdaterange_cbh(self):\n        # GH#62849\n        result = bdate_range(\n            "2009-03-13",\n            "2009-03-15",\n            freq="cbh",\n            weekmask="Mon Wed Fri",\n            holidays=["2009-03-14"],\n        )\n        expected = DatetimeIndex(\n            [\n                "2009-03-13 09:00:00",\n                "2009-03-13 10:00:00",\n                "2009-03-13 11:00:00",\n                "2009-03-13 12:00:00",\n                "2009-03-13 13:00:00",\n                "2009-03-13 14:00:00",\n                "2009-03-13 15:00:00",\n                "2009-03-13 16:00:00",\n            ],\n            dtype="datetime64[us]",\n            freq="cbh",\n        )\n        tm.assert_index_equal(result, expected)\n\n    def test_cdaterange_deprecated_error_CBH(self):\n        # GH#62849\n        msg = "invalid custom frequency string: CBH, did you mean cbh?"\n        with pytest.raises(ValueError, match=msg):\n            bdate_range(\n                START, END, freq="CBH", weekmask="Mon Wed Fri", holidays=["2009-03-14"]\n            )\n\n\nclass TestDateRangeNonNano:\n    def test_date_range_reso_validation(self):\n        msg = "\'unit\' must be one of \'s\', \'ms\', \'us\', \'ns\'"\n        with pytest.raises(ValueError, match=msg):\n            date_range("2016-01-01", "2016-03-04", periods=3, unit="h")\n\n    def test_date_range_freq_higher_than_reso(self):\n        # freq being higher-resolution than reso is a problem\n        msg = "Use a lower freq or a higher unit instead"\n        with pytest.raises(ValueError, match=msg):\n            #    # TODO give a more useful or informative message?\n            date_range("2016-01-01", "2016-01-02", freq="ns", unit="ms")\n\n    def test_date_range_freq_matches_reso(self):\n        # GH#49106 matching reso is OK\n        dti = date_range("2016-01-01", "2016-01-01 00:00:01", freq="ms", unit="ms")\n        rng = np.arange(1_451_606_400_000, 1_451_606_401_001, dtype=np.int64)\n        expected = DatetimeIndex(rng.view("M8[ms]"), freq="ms")\n        tm.assert_index_equal(dti, expected)\n\n        dti = date_range("2016-01-01", "2016-01-01 00:00:01", freq="us", unit="us")\n        rng = np.arange(1_451_606_400_000_000, 1_451_606_401_000_001, dtype=np.int64)\n        expected = DatetimeIndex(rng.view("M8[us]"), freq="us")\n        tm.assert_index_equal(dti, expected)\n\n        dti = date_range("2016-01-01", "2016-01-01 00:00:00.001", freq="ns", unit="ns")\n        rng = np.arange(\n            1_451_606_400_000_000_000, 1_451_606_400_001_000_001, dtype=np.int64\n        )\n        expected = DatetimeIndex(rng.view("M8[ns]"), freq="ns")\n        tm.assert_index_equal(dti, expected)\n\n    def test_date_range_freq_lower_than_endpoints(self):\n        start = Timestamp("2022-10-19 11:50:44.719781")\n        end = Timestamp("2022-10-19 11:50:47.066458")\n\n        # start and end cannot be cast to "s" unit without lossy rounding,\n        #  so we do not allow this in date_range\n        with pytest.raises(ValueError, match="Cannot losslessly convert units"):\n            date_range(start, end, periods=3, unit="s")\n\n        # but we can losslessly cast to "us"\n        dti = date_range(start, end, periods=2, unit="us")\n        rng = np.array(\n            [start.as_unit("us")._value, end.as_unit("us")._value], dtype=np.int64\n        )\n        expected = DatetimeIndex(rng.view("M8[us]"))\n        tm.assert_index_equal(dti, expected)\n\n    def test_date_range_non_nano(self):\n        start = np.datetime64("1066-10-14")  # Battle of Hastings\n        end = np.datetime64("2305-07-13")  # Jean-Luc Picard\'s birthday\n\n        dti = date_range(start, end, freq="D", unit="s")\n        assert dti.freq == "D"\n        assert dti.dtype == "M8[s]"\n\n        exp = np.arange(\n            start.astype("M8[s]").view("i8"),\n            (end + 1).astype("M8[s]").view("i8"),\n            24 * 3600,\n        ).view("M8[s]")\n\n        tm.assert_numpy_array_equal(dti.to_numpy(), exp)\n\n\nclass TestDateRangeNonTickFreq:\n    # Tests revolving around less-common (non-Tick) `freq` keywords.\n\n    def test_date_range_custom_business_month_begin(self, unit):\n        hcal = USFederalHolidayCalendar()\n        freq = offsets.CBMonthBegin(calendar=hcal)\n        dti = date_range(start="20120101", end="20130101", freq=freq, unit=unit)\n        assert all(freq.is_on_offset(x) for x in dti)\n\n        expected = DatetimeIndex(\n            [\n                "2012-01-03",\n                "2012-02-01",\n                "2012-03-01",\n                "2012-04-02",\n                "2012-05-01",\n                "2012-06-01",\n                "2012-07-02",\n                "2012-08-01",\n                "2012-09-04",\n                "2012-10-01",\n                "2012-11-01",\n                "2012-12-03",\n            ],\n            dtype=f"M8[{unit}]",\n            freq=freq,\n        )\n        tm.assert_index_equal(dti, expected)\n\n    def test_date_range_custom_business_month_end(self, unit):\n        hcal = USFederalHolidayCalendar()\n        freq = offsets.CBMonthEnd(calendar=hcal)\n        dti = date_range(start="20120101", end="20130101", freq=freq, unit=unit)\n        assert all(freq.is_on_offset(x) for x in dti)\n\n        expected = DatetimeIndex(\n            [\n                "2012-01-31",\n                "2012-02-29",\n                "2012-03-30",\n                "2012-04-30",\n                "2012-05-31",\n                "2012-06-29",\n                "2012-07-31",\n                "2012-08-31",\n                "2012-09-28",\n                "2012-10-31",\n                "2012-11-30",\n                "2012-12-31",\n            ],\n            dtype=f"M8[{unit}]",\n            freq=freq,\n        )\n        tm.assert_index_equal(dti, expected)\n\n    def test_date_range_with_custom_holidays(self, unit):\n        # GH#30593\n        freq = offsets.CustomBusinessHour(start="15:00", holidays=["2020-11-26"])\n        result = date_range(start="2020-11-25 15:00", periods=4, freq=freq, unit=unit)\n        expected = DatetimeIndex(\n            [\n                "2020-11-25 15:00:00",\n                "2020-11-25 16:00:00",\n                "2020-11-27 15:00:00",\n                "2020-11-27 16:00:00",\n            ],\n            dtype=f"M8[{unit}]",\n            freq=freq,\n        )\n        tm.assert_index_equal(result, expected)\n\n    def test_date_range_businesshour(self, unit):\n        idx = DatetimeIndex(\n            [\n                "2014-07-04 09:00",\n                "2014-07-04 10:00",\n                "2014-07-04 11:00",\n                "2014-07-04 12:00",\n                "2014-07-04 13:00",\n                "2014-07-04 14:00",\n                "2014-07-04 15:00",\n                "2014-07-04 16:00",\n            ],\n            dtype=f"M8[{unit}]",\n            freq="bh",\n        )\n        rng = date_range("2014-07-04 09:00", "2014-07-04 16:00", freq="bh", unit=unit)\n        tm.assert_index_equal(idx, rng)\n\n        idx = DatetimeIndex(\n            ["2014-07-04 16:00", "2014-07-07 09:00"], dtype=f"M8[{unit}]", freq="bh"\n        )\n        rng = date_range("2014-07-04 16:00", "2014-07-07 09:00", freq="bh", unit=unit)\n        tm.assert_index_equal(idx, rng)\n\n        idx = DatetimeIndex(\n            [\n                "2014-07-04 09:00",\n                "2014-07-04 10:00",\n                "2014-07-04 11:00",\n                "2014-07-04 12:00",\n                "2014-07-04 13:00",\n                "2014-07-04 14:00",\n                "2014-07-04 15:00",\n                "2014-07-04 16:00",\n                "2014-07-07 09:00",\n                "2014-07-07 10:00",\n                "2014-07-07 11:00",\n                "2014-07-07 12:00",\n                "2014-07-07 13:00",\n                "2014-07-07 14:00",\n                "2014-07-07 15:00",\n                "2014-07-07 16:00",\n                "2014-07-08 09:00",\n                "2014-07-08 10:00",\n                "2014-07-08 11:00",\n                "2014-07-08 12:00",\n                "2014-07-08 13:00",\n                "2014-07-08 14:00",\n                "2014-07-08 15:00",\n                "2014-07-08 16:00",\n            ],\n            dtype=f"M8[{unit}]",\n            freq="bh",\n        )\n        rng = date_range("2014-07-04 09:00", "2014-07-08 16:00", freq="bh", unit=unit)\n        tm.assert_index_equal(idx, rng)\n\n    def test_date_range_business_hour2(self, unit):\n        idx1 = date_range(\n            start="2014-07-04 15:00", end="2014-07-08 10:00", freq="bh", unit=unit\n        )\n        idx2 = date_range(start="2014-07-04 15:00", periods=12, freq="bh", unit=unit)\n        idx3 = date_range(end="2014-07-08 10:00", periods=12, freq="bh", unit=unit)\n        expected = DatetimeIndex(\n            [\n                "2014-07-04 15:00",\n                "2014-07-04 16:00",\n                "2014-07-07 09:00",\n                "2014-07-07 10:00",\n                "2014-07-07 11:00",\n                "2014-07-07 12:00",\n                "2014-07-07 13:00",\n                "2014-07-07 14:00",\n                "2014-07-07 15:00",\n                "2014-07-07 16:00",\n                "2014-07-08 09:00",\n                "2014-07-08 10:00",\n            ],\n            dtype=f"M8[{unit}]",\n            freq="bh",\n        )\n        tm.assert_index_equal(idx1, expected)\n        tm.assert_index_equal(idx2, expected)\n        tm.assert_index_equal(idx3, expected)\n\n        idx4 = date_range(\n            start="2014-07-04 15:45", end="2014-07-08 10:45", freq="bh", unit=unit\n        )\n        idx5 = date_range(start="2014-07-04 15:45", periods=12, freq="bh", unit=unit)\n        idx6 = date_range(end="2014-07-08 10:45", periods=12, freq="bh", unit=unit)\n\n        expected2 = expected + Timedelta(minutes=45).as_unit(unit)\n        expected2.freq = "bh"\n        tm.assert_index_equal(idx4, expected2)\n        tm.assert_index_equal(idx5, expected2)\n        tm.assert_index_equal(idx6, expected2)\n\n    def test_date_range_business_hour_short(self, unit):\n        # GH#49835\n        idx4 = date_range(start="2014-07-01 10:00", freq="bh", periods=1, unit=unit)\n        expected4 = DatetimeIndex(["2014-07-01 10:00"], dtype=f"M8[{unit}]", freq="bh")\n        tm.assert_index_equal(idx4, expected4)\n\n    def test_date_range_year_start(self, unit):\n        # see GH#9313\n        rng = date_range("1/1/2013", "7/1/2017", freq="YS", unit=unit)\n        exp = DatetimeIndex(\n            ["2013-01-01", "2014-01-01", "2015-01-01", "2016-01-01", "2017-01-01"],\n            dtype=f"M8[{unit}]",\n            freq="YS",\n        )\n        tm.assert_index_equal(rng, exp)\n\n    def test_date_range_year_end(self, unit):\n        # see GH#9313\n        rng = date_range("1/1/2013", "7/1/2017", freq="YE", unit=unit)\n        exp = DatetimeIndex(\n            ["2013-12-31", "2014-12-31", "2015-12-31", "2016-12-31"],\n            dtype=f"M8[{unit}]",\n            freq="YE",\n        )\n        tm.assert_index_equal(rng, exp)\n\n    def test_date_range_negative_freq_year_end(self, unit):\n        # GH#11018\n        rng = date_range("2011-12-31", freq="-2YE", periods=3, unit=unit)\n        exp = DatetimeIndex(\n            ["2011-12-31", "2009-12-31", "2007-12-31"], dtype=f"M8[{unit}]", freq="-2YE"\n        )\n        tm.assert_index_equal(rng, exp)\n        assert rng.freq == "-2YE"\n\n    def test_date_range_business_year_end_year(self, unit):\n        # see GH#9313\n        rng = date_range("1/1/2013", "7/1/2017", freq="BYE", unit=unit)\n        exp = DatetimeIndex(\n            ["2013-12-31", "2014-12-31", "2015-12-31", "2016-12-30"],\n            dtype=f"M8[{unit}]",\n            freq="BYE",\n        )\n        tm.assert_index_equal(rng, exp)\n\n    def test_date_range_bms(self, unit):\n        # GH#1645\n        result = date_range("1/1/2000", periods=10, freq="BMS", unit=unit)\n\n        expected = DatetimeIndex(\n            [\n                "2000-01-03",\n                "2000-02-01",\n                "2000-03-01",\n                "2000-04-03",\n                "2000-05-01",\n                "2000-06-01",\n                "2000-07-03",\n                "2000-08-01",\n                "2000-09-01",\n                "2000-10-02",\n            ],\n            dtype=f"M8[{unit}]",\n            freq="BMS",\n        )\n        tm.assert_index_equal(result, expected)\n\n    def test_date_range_semi_month_begin(self, unit):\n        dates = [\n            datetime(2007, 12, 15),\n            datetime(2008, 1, 1),\n            datetime(2008, 1, 15),\n            datetime(2008, 2, 1),\n            datetime(2008, 2, 15),\n            datetime(2008, 3, 1),\n            datetime(2008, 3, 15),\n            datetime(2008, 4, 1),\n            datetime(2008, 4, 15),\n            datetime(2008, 5, 1),\n            datetime(2008, 5, 15),\n            datetime(2008, 6, 1),\n            datetime(2008, 6, 15),\n            datetime(2008, 7, 1),\n            datetime(2008, 7, 15),\n            datetime(2008, 8, 1),\n            datetime(2008, 8, 15),\n            datetime(2008, 9, 1),\n            datetime(2008, 9, 15),\n            datetime(2008, 10, 1),\n            datetime(2008, 10, 15),\n            datetime(2008, 11, 1),\n            datetime(2008, 11, 15),\n            datetime(2008, 12, 1),\n            datetime(2008, 12, 15),\n        ]\n        # ensure generating a range with DatetimeIndex gives same result\n        result = date_range(start=dates[0], end=dates[-1], freq="SMS", unit=unit)\n        exp = DatetimeIndex(dates, dtype=f"M8[{unit}]", freq="SMS")\n        tm.assert_index_equal(result, exp)\n\n    def test_date_range_semi_month_end(self, unit):\n        dates = [\n            datetime(2007, 12, 31),\n            datetime(2008, 1, 15),\n            datetime(2008, 1, 31),\n            datetime(2008, 2, 15),\n            datetime(2008, 2, 29),\n            datetime(2008, 3, 15),\n            datetime(2008, 3, 31),\n            datetime(2008, 4, 15),\n            datetime(2008, 4, 30),\n            datetime(2008, 5, 15),\n            datetime(2008, 5, 31),\n            datetime(2008, 6, 15),\n            datetime(2008, 6, 30),\n            datetime(2008, 7, 15),\n            datetime(2008, 7, 31),\n            datetime(2008, 8, 15),\n            datetime(2008, 8, 31),\n            datetime(2008, 9, 15),\n            datetime(2008, 9, 30),\n            datetime(2008, 10, 15),\n            datetime(2008, 10, 31),\n            datetime(2008, 11, 15),\n            datetime(2008, 11, 30),\n            datetime(2008, 12, 15),\n            datetime(2008, 12, 31),\n        ]\n        # ensure generating a range with DatetimeIndex gives same result\n        result = date_range(start=dates[0], end=dates[-1], freq="SME", unit=unit)\n        exp = DatetimeIndex(dates, dtype=f"M8[{unit}]", freq="SME")\n        tm.assert_index_equal(result, exp)\n\n    def test_date_range_week_of_month(self, unit):\n        # GH#20517\n        # Note the start here is not on_offset for this freq\n        result = date_range(start="20110101", periods=1, freq="WOM-1MON", unit=unit)\n        expected = DatetimeIndex(["2011-01-03"], dtype=f"M8[{unit}]", freq="WOM-1MON")\n        tm.assert_index_equal(result, expected)\n\n        result2 = date_range(start="20110101", periods=2, freq="WOM-1MON", unit=unit)\n        expected2 = DatetimeIndex(\n            ["2011-01-03", "2011-02-07"], dtype=f"M8[{unit}]", freq="WOM-1MON"\n        )\n        tm.assert_index_equal(result2, expected2)\n\n    def test_date_range_week_of_month2(self, unit):\n        # GH#5115, GH#5348\n        result = date_range("2013-1-1", periods=4, freq="WOM-1SAT", unit=unit)\n        expected = DatetimeIndex(\n            ["2013-01-05", "2013-02-02", "2013-03-02", "2013-04-06"],\n            dtype=f"M8[{unit}]",\n            freq="WOM-1SAT",\n        )\n        tm.assert_index_equal(result, expected)\n\n    def test_date_range_negative_freq_month_end(self, unit):\n        # GH#11018\n        rng = date_range("2011-01-31", freq="-2ME", periods=3, unit=unit)\n        exp = DatetimeIndex(\n            ["2011-01-31", "2010-11-30", "2010-09-30"], dtype=f"M8[{unit}]", freq="-2ME"\n        )\n        tm.assert_index_equal(rng, exp)\n        assert rng.freq == "-2ME"\n\n    def test_date_range_fy5253(self, unit):\n        freq = offsets.FY5253(startingMonth=1, weekday=3, variation="nearest")\n        dti = date_range(\n            start="2013-01-01",\n            periods=2,\n            freq=freq,\n            unit=unit,\n        )\n        expected = DatetimeIndex(\n            ["2013-01-31", "2014-01-30"], dtype=f"M8[{unit}]", freq=freq\n        )\n\n        tm.assert_index_equal(dti, expected)\n\n    @pytest.mark.parametrize(\n        "freqstr,offset",\n        [\n            ("QS", offsets.QuarterBegin(startingMonth=1)),\n            ("BQE", offsets.BQuarterEnd(startingMonth=12)),\n            ("W-SUN", offsets.Week(weekday=6)),\n        ],\n    )\n    def test_date_range_freqstr_matches_offset(self, freqstr, offset):\n        sdate = datetime(1999, 12, 25)\n        edate = datetime(2000, 1, 1)\n\n        idx1 = date_range(start=sdate, end=edate, freq=freqstr)\n        idx2 = date_range(start=sdate, end=edate, freq=offset)\n        assert len(idx1) == len(idx2)\n        assert idx1.freq == idx2.freq\n\n    def test_date_range_partial_day_year_end(self, unit):\n        # GH#56134\n        rng = date_range(\n            start="2021-12-31 00:00:01",\n            end="2023-10-31 00:00:00",\n            freq="YE",\n            unit=unit,\n        )\n        exp = DatetimeIndex(\n            ["2021-12-31 00:00:01", "2022-12-31 00:00:01"],\n            dtype=f"M8[{unit}]",\n            freq="YE",\n        )\n        tm.assert_index_equal(rng, exp)\n\n    def test_date_range_negative_freq_year_end_inbounds(self, unit):\n        # GH#56147\n        rng = date_range(\n            start="2023-10-31 00:00:00",\n            end="2021-10-31 00:00:00",\n            freq="-1YE",\n            unit=unit,\n        )\n        exp = DatetimeIndex(\n            ["2022-12-31 00:00:00", "2021-12-31 00:00:00"],\n            dtype=f"M8[{unit}]",\n            freq="-1YE",\n        )\n        tm.assert_index_equal(rng, exp)\n\n    def test_date_range_tzaware_endpoints_accept_ambiguous(self):\n        # https://github.com/pandas-dev/pandas/issues/52908\n        start = Timestamp("1916-08-01", tz="Europe/Oslo")\n        end = Timestamp("1916-12-01", tz="Europe/Oslo")\n        res = date_range(start, end, freq="MS", ambiguous=True)\n        exp = date_range(\n            "1916-08-01", "1916-12-01", freq="MS", tz="Europe/Oslo", ambiguous=True\n        )\n        tm.assert_index_equal(res, exp)\n\n    def test_date_range_tzaware_endpoints_accept_nonexistent(self):\n        # Europe/London spring-forward: 2015-03-29 01:30 does not exist.\n        tz = "Europe/London"\n        start = Timestamp("2015-03-28 01:30", tz=tz)\n        end = Timestamp("2015-03-30 01:30", tz=tz)\n\n        result = date_range(start, end, freq="D", nonexistent="shift_forward")\n\n        # Build expected by generating naive daily times, then tz_localize so\n        # the nonexistent handling is applied during localization.\n        expected = date_range(\n            "2015-03-28 01:30", "2015-03-30 01:30", freq="D"\n        ).tz_localize(tz, nonexistent="shift_forward")\n        tm.assert_index_equal(result, expected)\n\n\nclass TestDateRangeUnitInference:\n    def test_date_range_unit_inference_matching_unit(self, unit):\n        start = Timestamp("2025-11-25").as_unit(unit)\n        end = Timestamp("2025-11-26").as_unit(unit)\n\n        dti = date_range(start, end, freq="D")\n        assert dti.unit == unit\n\n    def test_date_range_unit_inference_mismatched_unit(self, unit):\n        start = Timestamp("2025-11-25").as_unit(unit)\n        end = Timestamp("2025-11-26").as_unit("s")\n\n        dti = date_range(start, end, freq="D")\n        assert dti.unit == unit\n\n        dti = date_range(start, end.as_unit("ns"), freq="D")\n        assert dti.unit == "ns"\n\n    def test_date_range_unit_inference_tick(self):\n        start = Timestamp("2025-11-25").as_unit("ms")\n        end = Timestamp("2025-11-26").as_unit("s")\n\n        dti = date_range(start, end, freq="2000000us")\n        assert dti.unit == "us"\n\n        dti = date_range(start, end.as_unit("ns"), freq="2000000us")\n        assert dti.unit == "ns"\n\n    def test_date_range_unit_inference_dateoffset_freq(self):\n        start = Timestamp("2025-11-25 09:00:00").as_unit("s")\n        end = Timestamp("2025-11-25 09:00:02").as_unit("s")\n\n        off = DateOffset(microseconds=2_000_000)\n        dti = date_range(start, end, freq=off)\n        assert dti.unit == "us"\n\n        off = DateOffset(milliseconds=2)\n        dti = date_range(start, end, freq=off)\n        assert dti.unit == "ms"\n\n        end2 = start + Timedelta(microseconds=2).as_unit("us")\n        off = DateOffset(nanoseconds=2)\n        dti = date_range(start, end2, freq=off)\n        assert dti.unit == "ns"\n',
        }
